21	//===----------------------------------------------------------------------===//
22	// Deserialization registration
23	//===----------------------------------------------------------------------===//
24	
25	static OwningOpRef<Operation *> deserializeModule(llvm::StringRef bytecodeStr,
26	                                                  MLIRContext *context) {
27	  llvm::MemoryBufferRef bytecodeBufferRef(bytecodeStr,
28	                                          "deserializeModuleBuffer");
29	  auto dialect = context->getOrLoadDialect<CudaTileDialect>();
30	  dialect->setWarnUnsupportedHints(getWarnUnsupportedHints());
31	  dialect->setErrorOnHints(getErrorUnsupportedHints());
32	  return readBytecode(bytecodeBufferRef, *context);
33	}
34	
35	static void registerFromTileIRBytecodeTranslation() {
36	  TranslateToMLIRRegistration fromBytecode(
37	      "cudatilebc-to-mlir", "Translate CUDA Tile IR bytecode to MLIR",
38	      [](llvm::StringRef bytecode, MLIRContext *context) {
39	        return deserializeModule(bytecode, context);
40	      },
41	      [](DialectRegistry &registry) { registry.insert<CudaTileDialect>(); });
42	}
43	
44	//===----------------------------------------------------------------------===//
45	// Serialization registration
46	//===----------------------------------------------------------------------===//
47	static FailureOr<cuda_tile::ModuleOp> getCudaTileModuleOp(Operation *op) {
48	  cuda_tile::ModuleOp moduleOp = dyn_cast<cuda_tile::ModuleOp>(op);
49	  if (moduleOp)
50	    return moduleOp;
51	  // Also support a CUDA Tile IR Module nested in a MLIR Module for convenience
52	  // since the MLIR parse is adding one implicitly by default.
53	  if (auto moduleOp = dyn_cast<mlir::ModuleOp>(op)) {
54	    if (!llvm::hasSingleElement(*moduleOp.getBody()) ||
55	        !llvm::isa<cuda_tile::ModuleOp>(moduleOp.getBody()->front())) {
56	      return op->emitError(
57	          "expected a single CUDA Tile IR module in the MLIR module");
58	    }
59	    return cast<cuda_tile::ModuleOp>(moduleOp.getBody()->front());
60	  }
61	  return op->emitError("expected a CUDA Tile IR module, but got a " +
62	                       op->getName().getStringRef());
63	}
64	
65	static void registerToTileIRBytecodeTranslation() {
66	  TranslateFromMLIRRegistration toBytecode(
67	      "mlir-to-cudatilebc", "Translate MLIR to CUDA Tile IR bytecode",
68	      [](Operation *op, raw_ostream &output) {
69	        BytecodeVersion targetVersion = getCurrentBytecodeVersion();
70	        auto moduleOp = getCudaTileModuleOp(op);
71	        if (failed(moduleOp))
72	          return failure();
73	        auto dialect =
74	            cast<CudaTileDialect>(moduleOp->getOperation()->getDialect());
75	        dialect->setWarnUnsupportedHints(getWarnUnsupportedHints());
76	        dialect->setErrorOnHints(getErrorUnsupportedHints());
77	        return writeBytecode(output, *moduleOp, targetVersion);
78	      },
79	      [](DialectRegistry &registry) { registry.insert<CudaTileDialect>(); });
80	}
81	
82	void mlir::cuda_tile::registerTileIRTranslations() {
83	  registerFromTileIRBytecodeTranslation();
84	  registerToTileIRBytecodeTranslation();
85	}
