32	static constexpr const char *kOptimizationHints = "optimization_hints";
33	
34	//===----------------------------------------------------------------------===//
35	// Bytecode Format Overview
36	//===----------------------------------------------------------------------===//
37	// The bytecode format consists of a header followed by a sequence of sections.
38	// Each section has a specific format and purpose.
39	//
40	// bytecode =:
41	//   header
42	//   section*
43	//
44	// header =:
45	//   magic[8 bytes: 0x7F, 'T', 'i', 'l', 'e', 'I', 'R', 0x00]
46	//   version[varint]
47	//
48	// section =:
49	//   sectionId[byte]   // Lower 7 bits = ID, high bit = hasAlignment
50	//   length[varint]    // Length of section in bytes
51	//   alignment[varint] // Optional: only present if high bit of sectionId is set
52	//   padding[bytes]    // Optional: alignment padding bytes (0xCF)
53	//   data[bytes]       // Section-specific data format
54	//===----------------------------------------------------------------------===//
55	
56	//===----------------------------------------------------------------------===//
57	// EncodingWriter
58	// Provides utilities for writing encoded data to a stream.
59	//===----------------------------------------------------------------------===//
60	namespace {
61	class EncodingWriter {
62	public:
63	  EncodingWriter(raw_ostream &stream, uint64_t alignment = 1)
64	      : stream(stream), requiredAlignment(alignment) {}
65	
66	  void writeByte(uint8_t byte) { stream.write(static_cast<char>(byte)); }
67	
68	  template <typename Enum, std::enable_if_t<std::is_enum<Enum>::value, int> = 0>
69	  void writeByte(Enum value) {
70	    writeByte(static_cast<uint8_t>(value));
71	  }
72	
73	  void writeVarInt(uint64_t value) {
74	    uint8_t bytes[10]; // Supports up to 64 bits
75	    size_t index = 0;
76	
77	    do {
78	      uint8_t byte = value & 0x7F; // Lower 7 bits
79	      value >>= 7;
80	      if (value != 0)
81	        byte |= 0x80; // Set continuation bit
82	      bytes[index++] = byte;
83	    } while (value != 0 && index < sizeof(bytes));
84	
85	    stream.write(reinterpret_cast<char *>(bytes), index);
86	  }
87	
88	  template <typename Enum, std::enable_if_t<std::is_enum<Enum>::value, int> = 0>
89	  void writeVarInt(Enum value) {
90	    writeVarInt(static_cast<uint64_t>(value));
91	  }
92	
93	  /// Emit a signed variable length integer. Signed varints are encoded using
94	  /// a varint with zigzag encoding, meaning that we use the low bit of the
95	  /// value to indicate the sign of the value. This allows for more efficient
96	  /// encoding of negative values by limiting the number of active bits
97	  void writeSignedVarInt(uint64_t value) {
98	    writeVarInt((value << 1) ^ (uint64_t)((int64_t)value >> 63));
99	  }
100	
101	  template <typename T>
102	  std::enable_if_t<std::is_integral<T>::value, void> writeLE(T value) {
103	    for (size_t i = 0; i < sizeof(T); ++i) {
104	      writeByte(value & 0xFF);
105	      // Only shift if there are more bytes to process
106	      if (sizeof(T) > 1 && i < sizeof(T) - 1)
107	        value >>= 8;
108	    }
109	  }
110	
111	  template <typename T>
112	  void writeLE(ArrayRef<T> values) {
113	    for (T value : values)
114	      writeLE<T>(value);
115	  }
116	
117	  template <typename T>
118	  void writeLEVarSize(ArrayRef<T> values) {
119	    writeVarInt(values.size());
120	    writeLE(values);
121	  }
122	
123	  template <typename T>
124	  std::enable_if_t<std::is_floating_point<T>::value, void> writeLE(T value) {
125	    static_assert(std::numeric_limits<T>::is_iec559, "IEEE 754 required");
126	    using IntType = std::conditional_t<sizeof(T) == 4, uint32_t, uint64_t>;
127	    IntType intValue;
128	    std::memcpy(&intValue, &value, sizeof(T));
129	    for (size_t i = 0; i < sizeof(T); ++i) {
130	      writeByte(intValue & 0xFF);
131	      intValue >>= 8;
132	    }
133	  }
134	
135	  void write(const char *data, size_t size) { stream.write(data, size); }
136	
137	  void write(char c) { writeByte(static_cast<uint8_t>(c)); }
138	
139	  void write(StringRef str) { write(str.data(), str.size()); }
140	
141	  uint64_t tell() const { return stream.tell(); }
142	
143	  void alignTo(uint64_t alignment,
144	               uint8_t paddingByte = Bytecode::kAlignmentByte) {
145	    if (alignment < 2)
146	      return;
147	    uint64_t currentPos = tell();
148	    uint64_t padding = (alignment - (currentPos % alignment)) % alignment;
149	    for (uint64_t i = 0; i < padding; ++i)
150	      writeByte(paddingByte);
151	    // Update the required alignment
152	    requiredAlignment = std::max(requiredAlignment, alignment);
153	  }
154	  uint64_t getRequiredAlignment() const { return requiredAlignment; }
155	
156	private:
157	  raw_ostream &stream;
158	  uint64_t requiredAlignment = 1;
159	};
160	} // end anonymous namespace
161	
162	namespace {
163	struct BytecodeWriterConfig {
164	  BytecodeVersion bytecodeVersion;
165	};
166	} // end anonymous namespace
167	
168	//===----------------------------------------------------------------------===//
169	// Header Writer
170	//===----------------------------------------------------------------------===//
171	
172	static LogicalResult writeHeader(raw_ostream &stream, Operation *op,
173	                                 const BytecodeWriterConfig &config) {
174	  // Validate the bytecode version.
175	  if (config.bytecodeVersion < BytecodeVersion::kMinSupportedVersion) {
176	    return op->emitError() << "unsupported version requested "
177	                           << config.bytecodeVersion.toString()
178	                           << ", must be in range ["
179	                           << BytecodeVersion::kMinSupportedVersion.toString()
180	                           << ", "
181	                           << BytecodeVersion::kCurrentVersion.toString()
182	                           << ']';
183	  }
184	
185	  EncodingWriter writer(stream);
186	  const char magicNumber[8] = {0x7F, 'T', 'i', 'l', 'e', 'I', 'R', 0x00};
187	  writer.write(magicNumber, sizeof(magicNumber));
188	  writer.writeLE(config.bytecodeVersion.getMajor());
189	  writer.writeLE(config.bytecodeVersion.getMinor());
190	  writer.writeLE(config.bytecodeVersion.getTag());
191	
192	  return success();
193	}
194	
195	//===----------------------------------------------------------------------===//
196	// Section Header Writer
197	//===----------------------------------------------------------------------===//
198	
199	static void writeSectionHeader(raw_ostream &stream, uint8_t sectionID,
200	                               uint64_t length, uint64_t alignment) {
201	  EncodingWriter writer(stream);
202	  uint8_t idAndIsAligned = sectionID & 0x7F;
203	  if (alignment > 1)
204	    idAndIsAligned |= 0x80;
205	  writer.writeByte(idAndIsAligned);
206	  writer.writeVarInt(length);
207	  if (alignment > 1) {
208	    writer.writeVarInt(alignment);
209	    writer.alignTo(alignment);
210	  }
211	}
212	
213	/// Helper function to serialize an APInt.
214	static void writeAPInt(const APInt &apInt, EncodingWriter &writer) {
215	  unsigned bitWidth = apInt.getBitWidth();
216	  if (bitWidth <= 8) {
217	    writer.writeByte(static_cast<uint8_t>(apInt.getLimitedValue()));
218	  } else if (bitWidth <= 64) {
219	    writer.writeSignedVarInt(apInt.getLimitedValue());
220	  } else {
221	    unsigned numActiveWords = apInt.getActiveWords();
222	    writer.writeVarInt(numActiveWords);
223	    const uint64_t *rawValueData = apInt.getRawData();
224	    for (unsigned i = 0; i < numActiveWords; ++i)
225	      writer.writeSignedVarInt(rawValueData[i]);
226	  }
227	}
228	
229	/// Helper function to serialize the APFloat representation of a FloatAttr.
230	static void writeAPFloatRepresentation(const APFloat &apFloat,
231	                                       EncodingWriter &writer) {
232	  writeAPInt(apFloat.bitcastToAPInt(), writer);
233	}
