297	//===----------------------------------------------------------------------===//
298	// Type Section Management
299	// Collects and writes all unique types used in the module.
300	//===----------------------------------------------------------------------===//
301	// type-section =:
302	//   numTypes[varint]
303	//   padding[bytes]          // Align to 4 bytes
304	//   typeOffsets[uint32_t]   // Array of offsets, one per type
305	//   typeData[bytes]         // Concatenated type data
306	//
307	// type-data =:
308	//   typeTag[byte]           // Indicates the kind of type
309	//   type-specific-data      // Format depends on typeTag
310	//
311	// integer-type =: typeTag[I1/I32/I64]  // No additional data
312	// float-type =: typeTag[F32]           // No additional data
313	//
314	// tile-type =:
315	//   typeTag[Tile]
316	//   elementTypeIndex[varint]
317	//   rank[varint]
318	//   dimensions[int64_t*rank]
319	//
320	// function-type =:
321	//   typeTag[Func]
322	//   numInputs[varint]
323	//   inputTypeIndices[varint*numInputs]
324	//   numResults[varint]
325	//   resultTypeIndices[varint*numResults]
326	//
327	namespace {
328	struct TypeManager {
329	public:
330	  TypeManager(const BytecodeWriterConfig &config) : config(config) {}
331	
332	  // Gets or creates an index for a type in the type table.
333	  uint64_t getTypeIndex(Type type) {
334	    // Use the type's memory address as a unique key for lookup
335	    const void *key = type.getAsOpaquePointer();
336	    auto it = typeIndexMap.find(key);
337	    if (it != typeIndexMap.end())
338	      return it->second;
339	    // Ensure dependent/nested types are registered before the type itself
340	    registerDependentTypes(type);
341	    uint64_t index = typeList.size();
342	    typeIndexMap[key] = index;
343	    typeList.push_back(type);
344	    return index;
345	  }
346	
347	  LogicalResult writeTypeSection(raw_ostream &stream) {
348	    SmallVector<char> buffer;
349	    llvm::raw_svector_ostream sectionStream(buffer);
350	    EncodingWriter sectionWriter(sectionStream);
351	
352	    sectionWriter.writeVarInt(typeList.size());
353	    // Align the type section
354	    uint64_t alignmentNeeded = alignof(uint32_t);
355	    sectionWriter.alignTo(alignmentNeeded);
356	
357	    // Save the current position to fix up offsets later.
358	    auto offsetsPtr = sectionWriter.tell();
359	
360	    // Reserve space for the offset table (filled later).
361	    for (size_t i = 0; i < typeList.size(); ++i)
362	      sectionWriter.writeLE<uint32_t>(0);
363	
364	    // Write each type and record its starting offset.
365	    SmallVector<uint32_t> finalOffsets;
366	    finalOffsets.reserve(typeList.size());
367	
368	    uint32_t running = 0;
369	    for (Type type : typeList) {
370	      finalOffsets.push_back(running);
371	      auto before = sectionWriter.tell();
372	      if (failed(serializeType(type, sectionWriter)))
373	        return failure();
374	      running += static_cast<uint32_t>(sectionWriter.tell() - before);
375	    }
376	
377	    // Copy the pre-computed offsets into the reserved slot.
378	    std::copy_n(finalOffsets.begin(), finalOffsets.size(),
379	                reinterpret_cast<uint32_t *>(buffer.data() + offsetsPtr));
380	
381	    writeSectionHeader(stream, Bytecode::Section::Type, buffer.size(),
382	                       sectionWriter.getRequiredAlignment());
383	    stream.write(buffer.data(), buffer.size());
384	    return success();
385	  }
386	
387	  /// Helper function to write the index of a given type to the writer.
388	  LogicalResult writeTypeIndex(Type type, EncodingWriter &writer) {
389	    // Ensure type is registered and get its index.
390	    uint64_t index = getTypeIndex(type);
391	    writer.writeVarInt(index);
392	    return success();
393	  }
394	
395	private:
396	  // Include generated type serialization functions.
397	#define GEN_TYPE_WRITERS
398	#include "TypeBytecode.inc"
399	
400	  LogicalResult serializeType(Type type, EncodingWriter &writer){
401	  // Generated type serialization dispatch.
402	#define GEN_TYPE_WRITER_DISPATCH
403	#include "TypeBytecode.inc"
404	  }
405	
406	  LogicalResult
407	      serializeFunctionType(FunctionType type, EncodingWriter &writer) {
408	    // Write the function type with tag
409	    writer.writeVarInt(Bytecode::TypeTag::FunctionType);
410	    // Using VarInt for numParams per spec
411	    uint64_t numInputs = type.getNumInputs();
412	    writer.writeVarInt(numInputs);
413	    // Serialize input types
414	    for (Type input : type.getInputs())
415	      if (failed(writeTypeIndex(input, writer)))
416	        return failure();
417	    // Using VarInt for numResults per spec
418	    uint64_t numResults = type.getNumResults();
419	    writer.writeVarInt(numResults);
420	    // Serialize result types
421	    for (Type result : type.getResults())
422	      if (failed(writeTypeIndex(result, writer)))
423	        return failure();
424	    return success();
425	  }
426	
427	  // Helper to recursively register dependent types before the main type.
428	  void registerDependentTypes(Type type) {
429	    // Check if the type itself is already registered or being registered
430	    if (typeIndexMap.count(type.getAsOpaquePointer()))
431	      return;
432	
433	      // Auto-generated dependent type registration for CudaTile types.
434	#define GEN_DEPENDENT_TYPE_REGISTRATION
435	#include "TypeBytecode.inc"
436	
437	    // FunctionType is not a CudaTile type, handle it manually.
438	    if (auto funcType = dyn_cast<FunctionType>(type)) {
439	      for (Type input : funcType.getInputs())
440	        getTypeIndex(input);
441	      for (Type result : funcType.getResults())
442	        getTypeIndex(result);
443	    }
444	  }
445	
446	  llvm::MapVector<const void *, uint64_t> typeIndexMap;
447	  SmallVector<Type> typeList;
448	  const BytecodeWriterConfig &config;
449	};
450	} // end anonymous namespace
