452	//===----------------------------------------------------------------------===//
453	// Constant Section Management
454	//===----------------------------------------------------------------------===//
455	// constant-section =:
456	//   numConstants[varint]
457	//   padding[bytes]             // Align to 8 bytes
458	//   constantOffsets[uint64_t]  // Array of offsets, one per constant
459	//   constantData[bytes]        // Concatenated constant data
460	//
461	// constant-data format depends on the attribute type
462	// scalar-constant =: raw binary representation of the scalar value
463	//
464	namespace {
465	struct ConstantManager {
466	  LogicalResult addConstant(Attribute attr, uint64_t &index) {
467	    auto it = constantsMap.find(attr);
468	    if (it != constantsMap.end()) {
469	      index = std::distance(constantsMap.begin(), it);
470	      return success();
471	    }
472	    SmallVector<char> data;
473	    llvm::raw_svector_ostream dataStream(data);
474	    EncodingWriter writer(dataStream);
475	    if (failed(serializeAttribute(attr, writer)))
476	      return emitError(UnknownLoc::get(attr.getContext()),
477	                       "failed to serialize attribute");
478	    index = constantsMap.size();
479	    constantsMap[attr] = std::move(data);
480	    return success();
481	  }
482	
483	  // Look up a constant by attribute without adding it
484	  LogicalResult getConstantIndex(Attribute attr, uint64_t &index) const {
485	    auto it = constantsMap.find(attr);
486	    if (it != constantsMap.end()) {
487	      index = std::distance(constantsMap.begin(), it);
488	      return success();
489	    }
490	    return failure();
491	  }
492	
493	  // Provide access to the constant map
494	  const llvm::MapVector<Attribute, SmallVector<char>> &getConstantsMap() const {
495	    return constantsMap;
496	  }
497	
498	  /// Serializes a single MLIR attribute into its raw byte representation.
499	  /// This function handles different attribute types, focusing on scalar
500	  /// and dense element attributes suitable for the constant pool.
501	  LogicalResult serializeAttribute(Attribute attr, EncodingWriter &writer) {
502	    if (auto denseAttr = dyn_cast<DenseElementsAttr>(attr)) {
503	      // Get the raw data buffer in little-endian format.
504	      ArrayRef<char> rawData = denseAttr.getRawData();
505	      // Write the size of the raw buffer.
506	      writer.writeVarInt(rawData.size());
507	      // Write the raw buffer content.
508	      writer.write(rawData.data(), rawData.size());
509	      return success();
510	    } else if (auto intAttr = dyn_cast<IntegerAttr>(attr)) {
511	      APInt value = intAttr.getValue();
512	      writer.writeLE<uint64_t>(value.getZExtValue());
513	      return success();
514	    } else if (auto boolAttr = dyn_cast<BoolAttr>(attr)) {
515	      uint8_t boolValue = boolAttr.getValue() ? 0x01 : 0x00;
516	      writer.writeByte(boolValue);
517	      return success();
518	    } else if (auto floatAttr = dyn_cast<FloatAttr>(attr)) {
519	      writeAPFloatRepresentation(floatAttr.getValue(), writer);
520	      return success();
521	    }
522	    return emitError(UnknownLoc::get(attr.getContext()),
523	                     "unsupported attribute type in constant data");
524	  }
525	
526	  LogicalResult writeConstantSection(raw_ostream &stream) {
527	    // If there are no constants, skip writing this section entirely
528	    if (constantsMap.empty())
529	      return success();
530	    SmallVector<char> buffer;
531	    llvm::raw_svector_ostream sectionStream(buffer);
532	    EncodingWriter sectionWriter(sectionStream);
533	    // Write numConstants
534	    sectionWriter.writeVarInt(constantsMap.size());
535	    // Align the constant section
536	    uint64_t alignmentNeeded = alignof(uint64_t);
537	    sectionWriter.alignTo(alignmentNeeded);
538	
539	    // Save the current position to fix up offsets later.
540	    auto offsetsPtr = sectionWriter.tell();
541	
542	    // Reserve space for the offset table (filled later).
543	    for (size_t i = 0; i < constantsMap.size(); ++i)
544	      sectionWriter.writeLE<uint64_t>(0);
545	
546	    // Write each constant and record its starting offset.
547	    SmallVector<uint64_t> finalOffsets;
548	    finalOffsets.reserve(constantsMap.size());
549	
550	    uint64_t running = 0;
551	    for (const auto &pair : constantsMap) {
552	      if (pair.second.empty())
553	        return emitError(UnknownLoc::get(pair.first.getContext()))
554	               << "constant has empty serialized representation, which is "
555	                  "invalid";
556	      finalOffsets.push_back(running);
557	      sectionWriter.write(pair.second.data(), pair.second.size());
558	      running += pair.second.size();
559	    }
560	
561	    // Copy the pre-computed offsets into the reserved slot.
562	    std::copy_n(finalOffsets.begin(), finalOffsets.size(),
563	                reinterpret_cast<uint64_t *>(buffer.data() + offsetsPtr));
564	
565	    writeSectionHeader(stream, Bytecode::Section::Constant, buffer.size(),
566	                       sectionWriter.getRequiredAlignment());
567	    // Write the section content
568	    stream.write(buffer.data(), buffer.size());
569	    return success();
570	  }
571	
572	private:
573	  llvm::MapVector<Attribute, SmallVector<char>> constantsMap;
574	};
