1021	/// Helper macro for writing versioned CudaTile attribute tags.
1022	/// Performs version check and writes the tag if isSelfContained is true.
1023	/// Returns failure with an error message if the attribute is not available
1024	/// in the target bytecode version.
1025	/// Requires: op, isSelfContained, config, writer in scope.
1026	#define WRITE_VERSIONED_ATTR_TAG(TagName)                                      \
1027	  do {                                                                         \
1028	    if (isSelfContained) {                                                     \
1029	      if (!isAttrTagAvailableInVersion(                                        \
1030	              static_cast<uint8_t>(Bytecode::AttributeTag::TagName),           \
1031	              config.bytecodeVersion))                                         \
1032	        return op->emitError("attribute '" #TagName                            \
1033	                             "' is not available in bytecode version ")        \
1034	               << config.bytecodeVersion.toString();                           \
1035	      writer.writeVarInt(Bytecode::AttributeTag::TagName);                     \
1036	    }                                                                          \
1037	  } while (0)
1038	
1039	  // Writes the index or inline representation of an attribute.
1040	  // This function determines whether to serialize inline or use an index based
1041	  // on the attribute type.
1042	  LogicalResult
1043	  writeSingleAttribute(Operation *op, StringRef attrName, Attribute attrValue,
1044	                       EncodingWriter &writer, TypeManager &typeMgr,
1045	                       ConstantManager &constMgr, StringManager &strMgr,
1046	                       bool isSelfContained = false) {
1047	    return TypeSwitch<Attribute, LogicalResult>(attrValue)
1048	        .Case<TypeAttr>([&](TypeAttr typeAttr) {
1049	          // Handle TypeAttr: Write index using TypeManager
1050	          if (isSelfContained)
1051	            writer.writeVarInt(Bytecode::AttributeTag::Type);
1052	          return typeMgr.writeTypeIndex(typeAttr.getValue(), writer);
1053	        })
1054	        .Case<StringAttr>([&](StringAttr strAttr) {
1055	          // Handle StringAttr: Write index using StringManager
1056	          if (isSelfContained)
1057	            writer.writeVarInt(Bytecode::AttributeTag::String);
1058	          writer.writeVarInt(strMgr.getStringIndex(strAttr.getValue()));
1059	          return success();
1060	        })
1061	        .Case<IntegerAttr>([&](IntegerAttr intAttr) -> LogicalResult {
1062	          if (isSelfContained) {
1063	            writer.writeVarInt(Bytecode::AttributeTag::Integer);
1064	            if (failed(typeMgr.writeTypeIndex(intAttr.getType(), writer)))
1065	              return op->emitError(
1066	                  "failed to write type index for self-contained IntegerAttr");
1067	          }
1068	          writer.writeVarInt(intAttr.getValue().getZExtValue());
1069	          return success();
1070	        })
1071	        .Case<FloatAttr>([&](FloatAttr floatAttr) -> LogicalResult {
1072	          if (isSelfContained) {
1073	            writer.writeVarInt(Bytecode::AttributeTag::Float);
1074	            if (failed(typeMgr.writeTypeIndex(floatAttr.getType(), writer)))
1075	              return op->emitError(
1076	                  "failed to write type index for self-contained FloatAttr");
1077	          }
1078	          writeAPFloatRepresentation(floatAttr.getValue(), writer);
1079	          return success();
1080	        })
1081	        .Case<BoolAttr>([&](BoolAttr boolAttr) -> LogicalResult {
1082	          if (isSelfContained)
1083	            writer.writeVarInt(Bytecode::AttributeTag::Bool);
1084	          writer.writeByte(boolAttr.getValue() ? 0x01 : 0x00);
1085	          return success();
1086	        })
1087	        .Case<DenseElementsAttr>([&](DenseElementsAttr denseAttr)
1088	                                     -> LogicalResult {
1089	          if (isSelfContained) {
1090	            writer.writeVarInt(Bytecode::AttributeTag::DenseElements);
1091	            if (failed(typeMgr.writeTypeIndex(denseAttr.getType(), writer)))
1092	              return op->emitError(
1093	                  "failed to write type index for DenseElementsAttr");
1094	          }
1095	
1096	          if (auto intOrFPAttr =
1097	                  dyn_cast<DenseTypedElementsAttr>(denseAttr)) {
1098	            uint64_t constantIndex;
1099	            if (failed(constMgr.addConstant(intOrFPAttr, constantIndex)))
1100	              return op->emitError("failed to add constant attribute '")
1101	                     << attrName << "' to pool: " << intOrFPAttr;
1102	            writer.writeVarInt(constantIndex);
1103	            return success();
1104	          }
1105	
1106	          return op->emitError("unsupported DenseElementsAttr element type "
1107	                               "during serialization");
1108	        })
1109	        .Case<cuda_tile::DivByAttr>(
1110	            [&](cuda_tile::DivByAttr attr) -> LogicalResult {
1111	              WRITE_VERSIONED_ATTR_TAG(DivBy);
1112	              writer.writeVarInt(attr.getDivisor());
1113	              uint8_t flags = 0;
1114	              if (attr.getEvery().has_value())
1115	                flags |= 0x01;
1116	              if (attr.getAlong().has_value())
1117	                flags |= 0x02;
1118	              writer.writeByte(flags);
1119	
1120	              if (attr.getEvery().has_value())
1121	                writer.writeSignedVarInt(attr.getEvery().value());
1122	              if (attr.getAlong().has_value())
1123	                writer.writeSignedVarInt(attr.getAlong().value());
1124	              return success();
1125	            })
1126	        .Case<cuda_tile::SameElementsAttr>(
1127	            [&](cuda_tile::SameElementsAttr attr) -> LogicalResult {
1128	              WRITE_VERSIONED_ATTR_TAG(SameElements);
1129	              DenseI64ArrayAttr values = attr.getValues();
1130	              writer.writeLEVarSize(values.asArrayRef());
1131	              return success();
1132	            })
1133	        .Case<mlir::ArrayAttr>([&](mlir::ArrayAttr arrayAttr) -> LogicalResult {
1134	          if (isSelfContained)
1135	            writer.writeVarInt(Bytecode::AttributeTag::Array);
1136	          writer.writeVarInt(arrayAttr.size());
1137	          for (Attribute elementAttr : arrayAttr.getValue())
1138	            if (failed(writeSelfContainedAttribute(op, "arrayElement",
1139	                                                   elementAttr, writer, typeMgr,
1140	                                                   constMgr, strMgr)))
1141	              return op->emitError("failed to write ArrayAttr element: ")
1142	                     << elementAttr;
1143	          return success();
1144	        })
1145	        .Case<mlir::DictionaryAttr>([&](mlir::DictionaryAttr dictAttr)
1146	                                        -> LogicalResult {
1147	          if (isSelfContained)
1148	            writer.writeVarInt(Bytecode::AttributeTag::Dictionary);
1149	          writer.writeVarInt(dictAttr.size());
1150	          for (const NamedAttribute &namedAttr : dictAttr) {
1151	            writer.writeVarInt(strMgr.getStringIndex(namedAttr.getName()));
1152	            if (failed(writeSelfContainedAttribute(op, namedAttr.getName(),
1153	                                                   namedAttr.getValue(), writer,
1154	                                                   typeMgr, constMgr, strMgr)))
1155	              return op->emitError("failed to write DictionaryAttr element: ")
1156	                     << namedAttr.getValue();
1157	          }
1158	          return success();
1159	        })
1160	        .Case<cuda_tile::OptimizationHintsAttr>(
1161	            [&](cuda_tile::OptimizationHintsAttr optHintsAttr)
1162	                -> LogicalResult {
1163	              WRITE_VERSIONED_ATTR_TAG(OptimizationHints);
1164	              // OptimizationHintsAttr contains a DictionaryAttr.
1165	              return writeSingleAttribute(op, attrName, optHintsAttr.getValue(),
1166	                                          writer, typeMgr, constMgr, strMgr,
1167	                                          /*isSelfContained=*/false);
1168	            })
1169	        .Case<cuda_tile::BoundedAttr>([&](cuda_tile::BoundedAttr attr)
1170	                                          -> LogicalResult {
1171	          WRITE_VERSIONED_ATTR_TAG(Bounded);
1172	          uint8_t flags = 0;
1173	          if (attr.getLb().has_value())
1174	            flags |= 0x01;
1175	          if (attr.getUb().has_value())
1176	            flags |= 0x02;
1177	          writer.writeByte(flags);
1178	          if (attr.getLb().has_value())
1179	            writer.writeSignedVarInt(
1180	                static_cast<uint64_t>(attr.getLb().value()));
1181	          if (attr.getUb().has_value())
1182	            writer.writeSignedVarInt(
1183	                static_cast<uint64_t>(attr.getUb().value()));
1184	          return success();
1185	        })
1186	#ifdef TILE_IR_INCLUDE_TESTS
1187	        .Case<cuda_tile::BytecodeTestValueAttr>(
1188	            [&](cuda_tile::BytecodeTestValueAttr attr) -> LogicalResult {
1189	              WRITE_VERSIONED_ATTR_TAG(BytecodeTestValue);
1190	              writer.writeSignedVarInt(attr.getValue());
1191	              return success();
1192	            })
1193	#endif // TILE_IR_INCLUDE_TESTS
1194	        .Default([&](Attribute) -> LogicalResult {
1195	          // Default case: Error for unsupported types in this context
1196	          // TODO: Need to handle other potential attribute types if they occur
1197	          return op->emitError("unsupported attribute type encountered during "
1198	                               "serialization of attribute '")
