1318	  // Serializes the body of an op with a function interface to bytecode
1319	  LogicalResult writeFunctionBody(FunctionOpInterface func,
1320	                                  SmallVectorImpl<char> &functionBody) {
1321	    llvm::raw_svector_ostream bodyStream(functionBody);
1322	    EncodingWriter writer(bodyStream);
1323	    // Clear state for this function
1324	    valueIndexMap.clear();
1325	    nextValueIndex = 0;
1326	    // Process function arguments using the interface
1327	    for (BlockArgument arg : func.getArguments())
1328	      valueIndexMap[arg] = nextValueIndex++;
1329	    // Process operations using the interface
1330	    for (Block &block : func.getBlocks())
1331	      for (Operation &op : block.getOperations())
1332	        if (failed(writeOperation(&op, writer)))
1333	          return failure();
1334	    return success();
1335	  }
