1337	  /// Collect all function metadata.
1338	  LogicalResult buildFunctionMap(cuda_tile::ModuleOp module) {
1339	    // Get the body of the module, which contains the function definitions.
1340	    Block *moduleBody = &module.getBody().front();
1341	    if (!moduleBody) {
1342	      return module.emitError("module has no body.");
1343	    }
1344	
1345	    // Iterate through all operations in the module's body.
1346	    for (auto func : moduleBody->getOps<FunctionOpInterface>()) {
1347	      // Get the underlying operation pointer.
1348	      Operation *op = func.getOperation();
1349	
1350	      uint64_t nameIndex = strMgr.getStringIndex(func.getName());
1351	      uint64_t signatureIndex = typeMgr.getTypeIndex(func.getFunctionType());
1352	
1353	      uint64_t functionLocIndex = debuginfo.getOpIndex(op);
1354	      debuginfo.addDebugInfo(functionLocIndex, func.getLoc());
1355	
1356	      // Determine if it's an EntryOp
1357	      bool isEntry = isa<cuda_tile::EntryOp>(op);
1358	      Attribute hints;
1359	      if (auto entryOp = dyn_cast<cuda_tile::EntryOp>(op))
1360	        hints = entryOp.getOptimizationHintsAttr();
1361	
1362	      functionsMap[op] = FunctionMetadata{nameIndex, signatureIndex,
1363	                                          functionLocIndex, isEntry, hints};
1364	    }
1365	    return success();
1366	  }
