1368	  LogicalResult writeFunctionTableSection(raw_ostream &stream) {
1369	    SmallVector<char> buffer;
1370	    llvm::raw_svector_ostream sectionStream(buffer);
1371	    EncodingWriter sectionWriter(sectionStream);
1372	
1373	    sectionWriter.writeVarInt(functionsMap.size());
1374	
1375	    // Write function metadata and bodies
1376	    for (const auto &pair : functionsMap) {
1377	      Operation *op = pair.first;
1378	      const FunctionMetadata &meta = pair.second;
1379	
1380	      auto func = dyn_cast<mlir::FunctionOpInterface>(op);
1381	      assert(
1382	          func &&
1383	          "operation in functionsMap does not implement FunctionOpInterface.");
1384	
1385	      sectionWriter.writeVarInt(meta.nameIndex);
1386	      sectionWriter.writeVarInt(meta.signatureIndex);
1387	      // Write entryFlag.
1388	      uint8_t entryFlag = 0;
1389	      // TODO: Add support for visibility (Bit 0) when necessary.
1390	      // Assuming public for now.
1391	      if (meta.isEntry) {
1392	        entryFlag |= static_cast<uint8_t>(Bytecode::FunctionFlags::KindKernel);
1393	        if (meta.hints)
1394	          entryFlag |= static_cast<uint8_t>(
1395	              Bytecode::FunctionFlags::HasOptimizationHints);
1396	      }
1397	      sectionWriter.writeByte(entryFlag);
1398	      // Continue writing other metadata.
1399	      sectionWriter.writeVarInt(meta.functionLocIndex);
1400	
1401	      if (meta.isEntry && meta.hints) {
1402	        if (failed(writeSelfContainedAttribute(op, kOptimizationHints,
1403	                                               meta.hints, sectionWriter,
1404	                                               typeMgr, constMgr, strMgr)))
1405	          return failure();
1406	      }
1407	      SmallVector<char> functionBody;
1408	      if (failed(writeFunctionBody(func, functionBody)))
1409	        return failure();
1410	      sectionWriter.writeVarInt(functionBody.size());
1411	      sectionWriter.write(functionBody.data(), functionBody.size());
1412	    }
1413	    // Align the function section
1414	    uint64_t alignmentNeeded = alignof(uint64_t);
1415	    sectionWriter.alignTo(alignmentNeeded);
1416	    writeSectionHeader(stream, Bytecode::Section::Func, buffer.size(),
1417	                       sectionWriter.getRequiredAlignment());
1418	    stream.write(buffer.data(), buffer.size());
1419	    return success();
1420	  }
1421	
1422	  /// Handles writing regions.
1423	  /// region-bytecode =:
1424	  ///   numBlocks[varint]
1425	  ///   block-bytecode*
1426	  LogicalResult writeRegion(Region &region, EncodingWriter &writer) {
1427	    // Write the number of blocks in the region
1428	    writer.writeVarInt(region.getBlocks().size());
1429	
1430	    // Process each block in the region
1431	    for (Block &block : region)
1432	      if (failed(writeBlock(block, writer)))
1433	        return failure();
1434	
1435	    return success();
1436	  }
1437	
1438	  /// Handles writing blocks.
1439	  /// block-bytecode =:
1440	  ///   numArgs[varint]
1441	  ///   argTypeIndex[varint]*  // Type indices for each block argument.
1442	  ///   numOps[varint]
1443	  ///   instruction*           // Bytecode for each operation in the block.
1444	  LogicalResult writeBlock(Block &block, EncodingWriter &writer) {
1445	    // Record the current nextValueIndex. This will be restored after processing
1446	    // the block, effectively rolling back the indices used within this block.
1447	    uint64_t originalNextValueIndex = nextValueIndex;
1448	
1449	    // Process block arguments.
1450	    writer.writeVarInt(block.getNumArguments());
1451	    for (BlockArgument arg : block.getArguments()) {
1452	      if (failed(typeMgr.writeTypeIndex(arg.getType(), writer)))
1453	        return failure();
1454	      // Assign a new index to the block argument.
1455	      // Block arguments are always new values in this scope.
1456	      assert(!valueIndexMap.count(arg) &&
1457	             "block argument encountered that is already in valueIndexMap for "
1458	             "this scope");
1459	      valueIndexMap[arg] = nextValueIndex++;
1460	    }
1461	
1462	    // Write number of operations in the block.
1463	    writer.writeVarInt(block.getOperations().size());
1464	    // Process operations in the block.
1465	    for (Operation &op : block)
1466	      if (failed(writeOperation(&op, writer)))
1467	        return failure();
1468	
1469	    // Remove all of the entries added during parsing of this block.
1470	    for (uint64_t i = 0, e = nextValueIndex - originalNextValueIndex; i < e;
1471	         ++i)
1472	      valueIndexMap.pop_back();
1473	
1474	    // Restore nextValueIndex to what it was before this block.
1475	    nextValueIndex = originalNextValueIndex;
1476	    return success();
1477	  }
1478	
1479	private:
1480	  llvm::MapVector<Value, uint64_t> valueIndexMap;
1481	  uint64_t nextValueIndex = 0;
1482	
1483	  struct FunctionMetadata {
1484	    uint64_t nameIndex;
1485	    uint64_t signatureIndex;
1486	    uint64_t functionLocIndex;
1487	    bool isEntry;
1488	    Attribute hints;
1489	  };
1490	  llvm::MapVector<Operation *, FunctionMetadata> functionsMap;
1491	  TypeManager &typeMgr;
1492	  ConstantManager &constMgr;
1493	  StringManager &strMgr;
1494	  DebugInfoWriter &debuginfo;
1495	  const BytecodeWriterConfig &config;
1496	};
