60	//===----------------------------------------------------------------------===//
61	// Bytecode Format Overview
62	//===----------------------------------------------------------------------===//
63	// The bytecode format consists of a header followed by a sequence of sections.
64	// Each section has a specific format and purpose.
65	//
66	// bytecode =:
67	//   header
68	//   section*
69	//
70	// header =:
71	//   magic[8 bytes: 0x7F, 'T', 'i', 'l', 'e', 'I', 'R', 0x00]
72	//   version[varint]
73	//
74	// section =:
75	//   sectionId[byte]   // The lower 7 bits represent the ID, the high bit
76	//                     //   indicates alignment presence.
77	//   length[varint]    // The length of the section in bytes.
78	//   alignment[varint] // Optional: This field is only present
79	//                     //   if the high bit of sectionId is set.
80	//   padding[bytes]    // Optional: These are alignment padding bytes (0xCF).
81	//   data[bytes]       // The section-specific data format.
82	
83	//===----------------------------------------------------------------------===//
84	
85	//===----------------------------------------------------------------------===//
86	// EncodingReader: A helper class for reading encoded data from a byte buffer.
87	//===----------------------------------------------------------------------===//
88	namespace {
89	class EncodingReader {
90	public:
91	  EncodingReader(ArrayRef<uint8_t> data, MLIRContext &context)
92	      : data(data), offset(0), context(context) {}
93	
94	  LogicalResult readVarInt(uint64_t &result, uint64_t max = 0) {
95	    if (offset >= data.size())
96	      return failure();
97	    result = 0;
98	    uint64_t shift = 0;
99	    uint8_t byte;
100	    do {
101	      if (offset >= data.size() || shift > 63)
102	        return failure();
103	      byte = data[offset++];
104	      uint64_t value = byte & 0x7F;
105	      result |= (value << shift);
106	      shift += 7;
107	    } while (byte & 0x80);
108	    if (max && result > max)
109	      return emitError() << "varint value exceeds maximum supported"
110	                         << " capacity. (expected value less than " << max
111	                         << ", got " << result << ").";
112	    return success();
113	  }
114	
115	  /// Parse a signed variable length encoded integer from the byte stream. A
116	  /// signed varint is encoded as a normal varint with zigzag encoding applied,
117	  /// i.e. the low bit of the value is used to indicate the sign.
118	  LogicalResult readSignedVarInt(uint64_t &result) {
119	    if (failed(readVarInt(result)))
120	      return failure();
121	    // Essentially (but using unsigned): (x >> 1) ^ -(x & 1).
122	    result = (result >> 1) ^ (~(result & 1) + 1);
123	    return success();
124	  }
125	
126	  template <typename T>
127	  std::enable_if_t<std::is_integral<T>::value, LogicalResult> readLE(T &value) {
128	    if (offset + sizeof(T) > data.size())
129	      return failure();
130	    value = 0;
131	    for (size_t i = 0; i < sizeof(T); ++i)
132	      value |= static_cast<T>(data[offset++]) << (8 * i);
133	    return success();
134	  }
135	
136	  template <typename T>
137	  std::enable_if_t<std::is_integral<T>::value, T> readLE() {
138	    T value = 0;
139	    if (failed(readLE(value)))
140	      return 0;
141	    return value;
142	  }
143	
144	  template <typename T>
145	  std::enable_if_t<std::is_integral<T>::value, LogicalResult>
146	  readLE(size_t count, SmallVectorImpl<T> &result) {
147	    // Validate size to prevent excessive memory allocation.
148	    if (count > (std::numeric_limits<uint32_t>::max() - 1))
149	      return emitError() << "array size in bytecode (" << count
150	                         << ") exceeds maximum supported capacity";
151	    result.reserve(count);
152	    for (size_t i = 0; i < count; ++i) {
153	      T value;
154	      if (failed(readLE(value)))
155	        return failure();
156	      result.push_back(value);
157	    }
158	    return success();
159	  }
160	
161	  template <typename T>
162	  std::enable_if_t<std::is_integral<T>::value, LogicalResult>
163	  readLEVarSize(SmallVectorImpl<T> &result) {
164	    uint64_t size;
165	    if (failed(readVarInt(size)))
166	      return failure();
167	    return readLE(static_cast<size_t>(size), result);
168	  }
169	
170	  template <typename T>
171	  std::enable_if_t<std::is_floating_point<T>::value, LogicalResult>
172	  readLE(T &value) {
173	    static_assert(std::numeric_limits<T>::is_iec559, "IEEE 754 required");
174	    using IntType = std::conditional_t<sizeof(T) == 4, uint32_t, uint64_t>;
175	    IntType intValue;
176	    if (failed(readLE(intValue)))
177	      return failure();
178	    std::memcpy(&value, &intValue, sizeof(T));
179	    return success();
180	  }
181	
182	  template <typename T>
183	  std::enable_if_t<std::is_floating_point<T>::value, T> readLE() {
184	    T value = 0;
185	    if (failed(readLE(value)))
186	      return 0;
187	    return value;
188	  }
189	
190	  LogicalResult skip(size_t bytes) {
191	    if (offset + bytes > data.size())
192	      return failure();
193	    offset += bytes;
194	    return success();
195	  }
196	
197	  size_t remaining() const { return data.size() - offset; }
198	
199	  LogicalResult readBytes(size_t length, ArrayRef<uint8_t> &result) {
200	    if (offset + length > data.size()) {
201	      result = ArrayRef<uint8_t>();
202	      return failure();
203	    }
204	    result = data.slice(offset, length);
205	    offset += length;
206	    return success();
207	  }
208	
209	  ArrayRef<uint8_t> readBytes(size_t length) {
210	    ArrayRef<uint8_t> result;
211	    if (failed(readBytes(length, result)))
212	      return ArrayRef<uint8_t>();
213	    return result;
214	  }
215	
216	  const char *getCurrentPtr() const {
217	    if (offset >= data.size()) {
218	      return nullptr;
219	    }
220	    return reinterpret_cast<const char *>(data.data() + offset);
221	  }
222	
223	  LogicalResult getString(uint64_t index, StringRef &result,
224	                          MLIRContext &context) const {
225	    if (index >= stringOffsets.size())
226	      return ::emitError(UnknownLoc::get(&context))
227	             << "string index " << index << " out of bounds";
228	    uint32_t start = stringOffsets[index];
229	    uint32_t end = (index + 1 < stringOffsets.size())
230	                       ? stringOffsets[index + 1]
231	                       : static_cast<uint32_t>(stringData.size());
232	    result = stringData.substr(start, end - start);
233	    return success();
234	  }
235	
236	  /// Reads a string index and returns the corresponding StringRef.
237	  LogicalResult readAndGetString(StringRef &result) {
238	    uint64_t stringIndex;
239	    if (failed(readVarInt(stringIndex)))
240	      return failure();
241	    return getString(stringIndex, result, context);
242	  }
243	
244	  void setStringTable(StringRef data, ArrayRef<uint32_t> offsets) {
245	    stringData = data;
246	    stringOffsets = offsets;
247	  }
248	
249	  size_t currentOffset() const { return offset; }
250	
251	  LogicalResult skipPadding(uint64_t alignment) {
252	    if (alignment < 2)
253	      return success();
254	    if (remaining() == 0)
255	      return failure();
256	    size_t offset_position = this->currentOffset();
257	    size_t padding = (alignment - (offset_position % alignment)) % alignment;
258	    if (remaining() < padding)
259	      return failure();
260	    return skip(padding);
261	  }
262	
263	  // Emits an error message associated with the current reader offset.
264	  // TODO: Generate a location based on the current offset instead of
265	  // UnknownLoc.
266	  InFlightDiagnostic emitError() const {
267	    return ::emitError(UnknownLoc::get(&context))
268	           << "error at offset " << offset << ": ";
269	  }
270	
271	  void inheritStringTableFrom(const EncodingReader &masterReader) {
272	    this->stringData = masterReader.stringData;
273	    this->stringOffsets = masterReader.stringOffsets;
274	  }
275	
276	private:
277	  ArrayRef<uint8_t> data;
278	  size_t offset;
279	  StringRef stringData;
280	  ArrayRef<uint32_t> stringOffsets;
281	  MLIRContext &context;
282	};
283	} // end anonymous namespace
