285	//===----------------------------------------------------------------------===//
286	// Header Parsing
287	//===----------------------------------------------------------------------===//
288	namespace {
289	struct SectionHeader {
290	  uint8_t sectionID = Section::EndOfBytecode;
291	  uint64_t length = 0;
292	  bool hasAlignment = false;
293	  uint64_t alignment = 1;
294	};
295	} // end anonymous namespace
296	
297	/// Parses and validates the bytecode header, including the magic number and
298	/// version.
299	static LogicalResult parseHeader(EncodingReader &reader, MLIRContext &context,
300	                                 BytecodeVersion &version) {
301	  // Read and verify the magic number.
302	  for (int i = 0, e = std::size(kTileIRBytecodeMagic); i < e; ++i) {
303	    uint8_t byte = reader.readLE<uint8_t>();
304	    if (byte != kTileIRBytecodeMagic[i])
305	      return reader.emitError()
306	             << "invalid magic number at position " << i << ", got "
307	             << static_cast<int>(byte) << " expected "
308	             << static_cast<int>(kTileIRBytecodeMagic[i]);
309	  }
310	  /// Read and verify the version number.
311	  uint8_t verMajor, verMinor;
312	  uint16_t tag;
313	  if (failed(reader.readLE(verMajor)) || failed(reader.readLE(verMinor)) ||
314	      failed(reader.readLE(tag)))
315	    return failure();
316	  // Check if the version is supported.
317	  std::optional<BytecodeVersion> versionInfo =
318	      BytecodeVersion::fromVersion(verMajor, verMinor, tag);
319	  if (!versionInfo || *versionInfo < BytecodeVersion::kMinSupportedVersion) {
320	    return reader.emitError()
321	           << "unsupported Tile version " << verMajor << "." << verMinor << "."
322	           << tag << ", this reader supports versions ["
323	           << BytecodeVersion::kMinSupportedVersion.toString() << " - "
324	           << BytecodeVersion::kCurrentVersion.toString() << "]";
325	  }
326	  version = *versionInfo;
327	  return success();
328	}
329	
330	/// Parses the section header from the bytecode.
331	static LogicalResult parseSectionHeader(EncodingReader &reader,
332	                                        SectionHeader &header,
333	                                        MLIRContext &context) {
334	  if (reader.remaining() < 1)
335	    return reader.emitError()
336	           << "unexpected end of data while reading section header";
337	  uint8_t idAndIsAligned;
338	  if (failed(reader.readLE(idAndIsAligned)))
339	    return reader.emitError() << "failed to read section ID and alignment flag";
340	  header.sectionID = idAndIsAligned & 0x7F;
341	  header.hasAlignment = (idAndIsAligned & 0x80) != 0;
342	
343	  // If this is the end section marker, return success.
344	  if (header.sectionID == Section::EndOfBytecode) {
345	    if (header.hasAlignment)
346	      return reader.emitError()
347	             << "end section should not have alignment flag set";
348	    return success();
349	  }
350	  if (header.sectionID >= Section::NumSections)
351	    return reader.emitError() << "unknown section ID: " << header.sectionID;
352	
353	  // Read the section length.
354	  if (failed(reader.readVarInt(header.length)))
355	    return reader.emitError() << "failed to read section length";
356	  if (header.length > reader.remaining())
357	    return reader.emitError()
358	           << "section length " << header.length
359	           << " exceeds remaining data size " << reader.remaining();
360	
361	  // If the section is aligned, read the alignment value and adjust the buffer.
362	  if (header.hasAlignment) {
363	    if (failed(reader.readVarInt(header.alignment)))
364	      return failure();
365	    if (header.alignment == 0 || !llvm::isPowerOf2_64(header.alignment))
366	      return reader.emitError()
367	             << "invalid alignment value: " << header.alignment;
368	    if (failed(reader.skipPadding(header.alignment)))
369	      return failure();
370	  }
371	  return success();
372	}
373	
374	//===----------------------------------------------------------------------===//
375	// String Section
376	//===----------------------------------------------------------------------===//
377	// string-section =:
378	//   numStrings[varint]
379	//   padding[bytes]            // Align to 4 bytes
380	//   stringOffsets[uint32_t]   // Array of offsets, one per string
381	//   stringData[bytes]         // Concatenated string data
382	//
383	/// Parses the string section and sets up the string table for lazy loading.
384	static LogicalResult parseStringSection(ArrayRef<uint8_t> payload,
385	                                        EncodingReader &reader,
386	                                        MLIRContext &context) {
387	  EncodingReader sectionReader(payload, context);
388	  uint64_t numStrings;
389	  if (failed(sectionReader.readVarInt(numStrings)))
390	    return failure();
391	
392	  // Handle empty string table case.
393	  if (numStrings == 0) {
394	    reader.setStringTable(StringRef(), ArrayRef<uint32_t>());
395	    return success();
396	  }
397	
398	  if (numStrings >
399	      (payload.size() - sectionReader.currentOffset()) / sizeof(uint32_t)) {
400	    return sectionReader.emitError()
401	           << "number of strings (" << numStrings << ") exceeds the maximum of "
402	           << (payload.size() - sectionReader.currentOffset()) /
403	                  sizeof(uint32_t)
404	           << " that can fit in the remaining payload of "
405	           << (payload.size() - sectionReader.currentOffset()) << " bytes.";
406	  }
407	
408	  // Ensure 4-byte alignment for the start indices array.
409	  if (failed(sectionReader.skipPadding(alignof(uint32_t))))
410	    return failure();
411	  // Read the string offsets directly from the payload.
412	  const uint32_t *startIndicesPtr =
413	      reinterpret_cast<const uint32_t *>(sectionReader.getCurrentPtr());
414	  if (!startIndicesPtr)
415	    return failure();
416	  ArrayRef<uint32_t> stringOffsets(startIndicesPtr, numStrings);
417	  if (failed(sectionReader.skip(numStrings * sizeof(uint32_t))))
418	    return failure();
419	  // Get the string data
420	  StringRef stringData(
421	      reinterpret_cast<const char *>(sectionReader.getCurrentPtr()),
422	      sectionReader.remaining());
423	  // Set up the string table in the main reader.
424	  reader.setStringTable(stringData, stringOffsets);
425	  return success();
426	}
