466	//===----------------------------------------------------------------------===//
467	// LazyTypeTable: Manages lazy parsing and caching of types from the type
468	// section.
469	//===----------------------------------------------------------------------===//
470	// type-section =:
471	//   numTypes[varint]
472	//   padding[bytes]          // Align to 4 bytes
473	//   typeOffsets[uint32_t]   // Array of offsets, one per type
474	//   typeData[bytes]         // Concatenated type data
475	//
476	// type-data =:
477	//   typeTag[byte]           // Indicates the kind of type
478	//   type-specific-data      // Format depends on typeTag
479	//
480	namespace {
481	class LazyTypeTable {
482	public:
483	  LazyTypeTable(MLIRContext &context) : context(context) {}
484	
485	  void initialize(ArrayRef<uint8_t> payloadData, ArrayRef<uint32_t> indices,
486	                  const BytecodeVersion &version) {
487	    payload = payloadData;
488	    typeStartIndices = indices;
489	    typeCache.resize(indices.size());
490	    fileVersion = version;
491	  }
492	
493	  Type getType(uint64_t typeIndex) {
494	    if (typeIndex >= typeCache.size())
495	      return Type();
496	    if (typeCache[typeIndex])
497	      return typeCache[typeIndex];
498	
499	    // Check for recursion.
500	    if (currentlyParsing.count(typeIndex))
501	      return Type();
502	    // Mark this type as currently being parsed.
503	    currentlyParsing.insert(typeIndex);
504	    [[maybe_unused]] llvm::scope_exit removeIndex(
505	        [&] { currentlyParsing.erase(typeIndex); });
506	    // Calculate the boundaries for the type data.
507	    uint32_t start = typeStartIndices[typeIndex];
508	    uint32_t end = (typeIndex + 1 < typeStartIndices.size())
509	                       ? typeStartIndices[typeIndex + 1]
510	                       : payload.size();
511	    if (end < start || end > payload.size())
512	      return Type();
513	    // Parse the type from its specific byte slice.
514	    EncodingReader typeReader(payload.slice(start, end - start), context);
515	    uint64_t typeTag;
516	    if (failed(typeReader.readVarInt(typeTag)))
517	      return nullptr;
518	    ArrayRef<uint8_t> payloadBytes;
519	    if (typeReader.remaining() > 0)
520	      payloadBytes = typeReader.readBytes(typeReader.remaining());
521	    Type parsedType;
522	    if (failed(parseTypeImpl(typeTag, payloadBytes, parsedType)))
523	      return Type();
524	
525	    // Cache the result.
526	    typeCache[typeIndex] = parsedType;
527	    return parsedType;
528	  }
529	
530	  size_t size() const { return typeStartIndices.size(); }
531	
532	  /// Returns the bytecode file version.
533	  BytecodeVersion getFileVersion() const { return fileVersion; }
534	
535	  /// Reads a type index using the provided reader and retrieves the
536	  /// corresponding Type. Emits an error and returns a null Type on failure.
537	  Type readAndGetType(EncodingReader &reader) {
538	    uint64_t typeIndex;
539	    if (failed(reader.readVarInt(typeIndex))) {
540	      return Type();
541	    }
542	    // getType already emits an error if the index is bad or parsing fails.
543	    return getType(typeIndex);
544	  }
545	
546	private:
547	  // All type deserialization is now auto-generated - see
548	  // TypeBytecodeReader.inc.
549	#define GEN_TYPE_READERS
550	#include "TypeBytecodeReader.inc"
551	
552	  // function-type =:
553	  //   typeTag[Func]
554	  //   numInputs[varint]
555	  //   inputTypeIndices[varint*numInputs]
556	  //   numResults[varint]
557	  //   resultTypeIndices[varint*numResults]
558	  LogicalResult parseFunctionType(EncodingReader &reader, Type &result) {
559	    uint64_t numParams, numResults;
560	    // Read the number of parameters (VarInt as per specification).
561	    if (failed(reader.readVarInt(numParams,
562	                                 std::numeric_limits<uint32_t>::max() - 1)))
563	      return reader.emitError() << "failed to read number of parameters";
564	
565	    // Read parameter types
566	    SmallVector<Type, 4> paramTypes;
567	    paramTypes.reserve(numParams);
568	    for (uint64_t i = 0; i < numParams; ++i) {
569	      Type paramType = readAndGetType(reader);
570	      if (!paramType)
571	        return reader.emitError() << "failed to get parameter type";
572	      paramTypes.push_back(paramType);
573	    }
574	    //  Read the number of results (VarInt as per specification).
575	    if (failed(reader.readVarInt(numResults,
576	                                 std::numeric_limits<uint32_t>::max() - 1)))
577	      return reader.emitError() << "failed to read number of results";
578	    // Read result types
579	    SmallVector<Type, 4> resultTypes;
580	    resultTypes.reserve(numResults);
581	    for (uint64_t i = 0; i < numResults; ++i) {
582	      Type resultType = readAndGetType(reader);
583	      if (!resultType)
584	        return reader.emitError() << "failed to get result type";
585	      resultTypes.push_back(resultType);
586	    }
587	    result = FunctionType::get(&context, paramTypes, resultTypes);
588	    return success();
589	  }
590	
591	  LogicalResult parseTypeImpl(uint8_t typeTag, ArrayRef<uint8_t> payloadBytes,
592	                              Type &result) {
593	    EncodingReader reader(payloadBytes, context);
594	    // Generated complete switch statement.
595	#define GEN_TYPE_READER_DISPATCH
596	#include "TypeBytecodeReader.inc"
597	  }
598	
599	  MLIRContext &context;
600	  ArrayRef<uint8_t> payload;
601	  ArrayRef<uint32_t> typeStartIndices;
602	  std::vector<Type> typeCache;
603	  DenseSet<uint64_t> currentlyParsing;
604	  BytecodeVersion fileVersion;
605	};
606	} // end anonymous namespace
607	
608	/// Parses the type section and initializes the lazy type table
609	static LogicalResult parseTypeSection(ArrayRef<uint8_t> payload,
610	                                      LazyTypeTable &types,
611	                                      MLIRContext &context,
612	                                      const BytecodeVersion &bytecodeVersion) {
613	  EncodingReader reader(payload, context);
614	  uint64_t numTypes;
615	  if (failed(reader.readVarInt(numTypes)))
616	    return failure();
617	
618	  // Handle empty type table case.
619	  if (numTypes == 0) {
620	    types.initialize(ArrayRef<uint8_t>(), ArrayRef<uint32_t>(),
621	                     bytecodeVersion);
622	    return success();
623	  }
624	
625	  if (numTypes > (payload.size() - reader.currentOffset()) / sizeof(uint32_t)) {
626	    return reader.emitError()
627	           << "number of types (" << numTypes << ") exceeds the maximum of "
628	           << (payload.size() - reader.currentOffset()) / sizeof(uint32_t)
629	           << " that can fit in the remaining payload of "
630	           << (payload.size() - reader.currentOffset()) << " bytes.";
631	  }
632	
633	  // Ensure 4-byte alignment for the start indices array
634	  if (failed(reader.skipPadding(alignof(uint32_t))))
635	    return failure();
636	  // Read type start indices as a contiguous array
637	  const uint32_t *startIndicesPtr =
638	      reinterpret_cast<const uint32_t *>(reader.getCurrentPtr());
639	  if (!startIndicesPtr)
640	    return failure();
641	  ArrayRef<uint32_t> typeStartIndices(startIndicesPtr, numTypes);
642	  if (failed(reader.skip(numTypes * sizeof(uint32_t))))
643	    return failure();
644	  // Initialize the lazy type table with the payload and indices
645	  ArrayRef<uint8_t> typeData = payload.slice(reader.currentOffset());
646	  types.initialize(typeData, typeStartIndices, bytecodeVersion);
647	  return success();
648	}
