650	//===----------------------------------------------------------------------===//
651	// Constant Section
652	//===----------------------------------------------------------------------===//
653	// constant-section =:
654	//   numConstants[varint]
655	//   padding[bytes]             // Align to 8 bytes
656	//   constantOffsets[uint64_t]  // Array of offsets, one per constant
657	//   constantData[bytes]        // Concatenated constant data
658	//
659	// constant-data format depends on the attribute type
660	// scalar-constant =: raw binary representation of the scalar value
661	//
662	namespace {
663	///  A cache for deduplicating constant attributes during parsing.
664	class DenseElementsAttrCache {
665	public:
666	  FailureOr<DenseElementsAttr> getOrCreate(Type type, ArrayRef<uint8_t> data,
667	                                           MLIRContext &context) {
668	    // The key is a combination of the expected type and the raw data blob.
669	    std::pair<Type, ArrayRef<uint8_t>> key = {type, data};
670	    auto it = cache.find(key);
671	    if (it != cache.end())
672	      return it->second;
673	
674	    // Create a reader for the constant data blob.
675	    EncodingReader reader(data, context);
676	
677	    // Cast to TileType to get element type and shape info.
678	    if (!type)
679	      return reader.emitError() << "provided type is null";
680	    auto tileType = mlir::dyn_cast<cuda_tile::TileType>(type);
681	    if (!tileType || !tileType.getElementType().isIntOrFloat())
682	      return reader.emitError()
683	             << "expect Cuda Tile integer or float type but got: " << tileType;
684	
685	    // Read the size of the raw data buffer.
686	    uint64_t rawDataSize;
687	    if (failed(reader.readVarInt(rawDataSize)))
688	      return reader.emitError() << "failed to read the size of the data buffer";
689	
690	    // Read the raw byte data.
691	    ArrayRef<uint8_t> rawUint8Data;
692	    if (failed(reader.readBytes(rawDataSize, rawUint8Data)))
693	      return reader.emitError() << "failed to read the raw byte data";
694	
695	    // Convert ArrayRef<uint8_t> to ArrayRef<char>.
696	    ArrayRef<char> rawData(reinterpret_cast<const char *>(rawUint8Data.data()),
697	                           rawUint8Data.size());
698	    // Validate the buffer size and format.
699	    if (!DenseElementsAttr::isValidRawBuffer(tileType, rawData)) {
700	      return reader.emitError() << "failed to validate buffer size and format";
701	    }
702	
703	    DenseElementsAttr attr = nullptr;
704	    // Handle endianness conversion.
705	    if (llvm::endianness::native == llvm::endianness::big) {
706	      // Convert endianess.
707	      SmallVector<char, 64> outDataVec(rawData.size());
708	      MutableArrayRef<char> convRawData(outDataVec);
709	      DenseTypedElementsAttr::convertEndianOfArrayRefForBEmachine(
710	          rawData, convRawData, tileType);
711	      attr = DenseElementsAttr::getFromRawBuffer(tileType, convRawData);
712	    } else {
713	      attr = DenseElementsAttr::getFromRawBuffer(tileType, rawData);
714	    }
715	
716	    if (attr)
717	      cache.insert({key, attr});
718	    return attr;
719	  }
720	
721	private:
722	  DenseMap<std::pair<Type, ArrayRef<uint8_t>>, DenseElementsAttr> cache;
723	};
724	} // namespace
725	
726	/// Parses the constant section and populates the constant table
727	static LogicalResult
728	parseConstantSection(ArrayRef<uint8_t> payload,
729	                     std::vector<ArrayRef<uint8_t>> &constants,
730	                     MLIRContext &context) {
731	  EncodingReader reader(payload, context);
732	  uint64_t numConstants;
733	  if (failed(reader.readVarInt(numConstants,
734	                               std::numeric_limits<uint32_t>::max() - 1)))
735	    return failure();
736	  // Handle empty constant section case
737	  if (numConstants == 0)
738	    return success();
739	  // Ensure 8-byte alignment for the start indices array
740	  if (failed(reader.skipPadding(alignof(uint64_t))))
741	    return failure();
742	  // Check if we have enough data to read the indices
743	  if (reader.remaining() / sizeof(uint64_t) < numConstants)
744	    return reader.emitError() << "insufficient data for constant indices";
745	
746	  // Read constant start indices as a contiguous array
747	  const uint64_t *startIndicesPtr =
748	      reinterpret_cast<const uint64_t *>(reader.getCurrentPtr());
749	  if (!startIndicesPtr)
750	    return failure();
751	
752	  ArrayRef<uint64_t> constantStartIndices(startIndicesPtr, numConstants);
753	  if (failed(reader.skip(constantStartIndices.size() * sizeof(uint64_t))))
754	    return failure();
755	  ArrayRef<uint8_t> constantData = payload.slice(reader.currentOffset());
756	  // Populate constants based on constantStartIndices
757	  constants.reserve(numConstants);
758	  for (uint64_t i = 0; i < numConstants; ++i) {
759	    uint64_t start = constantStartIndices[i];
760	    uint64_t end = (i + 1 < numConstants) ? constantStartIndices[i + 1]
761	                                          : constantData.size();
762	    if (end < start)
763	      return reader.emitError()
764	             << "invalid constant start indices: end (" << end
765	             << ") is less than start (" << start << ") for constant " << i;
766	    size_t constantSize = end - start;
767	    if (constantSize + start > constantData.size())
768	      return reader.emitError()
769	             << "constant " << i << " extends beyond available data: "
770	             << "size=" << constantSize << ", start=" << start
771	             << ", total data size=" << constantData.size();
772	    constants.push_back(constantData.slice(start, constantSize));
773	  }
774	  return success();
775	}
