783	/// This class manages reading debug info attributes from bytecode format.
784	class DebugInfoReader {
785	public:
786	  DebugInfoReader(MLIRContext &context, EncodingReader &masterReader)
787	      : context(context), masterReader(masterReader) {}
788	
789	  class Iterator {
790	  public:
791	    Iterator(DebugInfoReader &reader, uint64_t opIndex)
792	        : reader(reader), opIndex(opIndex) {}
793	
794	    /// Return the next debug info attribute for the current operation.
795	    template <typename T>
796	    T next() {
797	      // Check if the index is reserved for special debug info attributes.
798	      if (opIndex == static_cast<uint64_t>(Bytecode::DebugReserved::UnknownLoc))
799	        return dyn_cast<T>(UnknownLoc::get(&reader.context));
800	
801	      // Adjust the index to account for reserved indices.
802	      auto actualOpIndex =
803	          opIndex - static_cast<uint64_t>(Bytecode::DebugReserved::SIZE);
804	
805	      // Calculate the offset for the current operation index.
806	      if (actualOpIndex >= reader.diIndexOffsets.size())
807	        return T();
808	      auto offset = reader.diIndexOffsets[actualOpIndex];
809	
810	      // Validate size to prevent excessive memory allocation.
811	      if (reader.diIndices.size() > (std::numeric_limits<uint32_t>::max() - 1))
812	        return T();
813	      if (offset > (std::numeric_limits<uint32_t>::max() - 1))
814	        return T();
815	      if (offset + opIndexOffset >= reader.diIndices.size())
816	        return T();
817	      offset += opIndexOffset++;
818	
819	      // Return the next debug info attribute for the current operation.
820	      return reader.getDebugInfo<T>(reader.diIndices[offset]);
821	    }
822	
823	  private:
824	    DebugInfoReader &reader;
825	    uint64_t opIndex;
826	    uint64_t opIndexOffset = 0;
827	  };
828	
829	  Iterator getIterator(uint64_t opIndex) { return Iterator(*this, opIndex); }
830	
831	  /// This method initializes the debug info reader after construction.
832	  void initialize(ArrayRef<uint64_t> indices, ArrayRef<uint32_t> indexOffsets,
833	                  ArrayRef<uint8_t> data, ArrayRef<uint32_t> offsets) {
834	    diIndices = indices;
835	    diIndexOffsets = indexOffsets;
836	    diData = data;
837	    diOffsets = offsets;
838	    diCache.resize(offsets.size());
839	  }
840	
841	private:
842	  /// This method returns a debug info attribute for a given index.
843	  template <typename T>
844	  T getDebugInfo(uint64_t diIndex) {
845	    // Check if the index is reserved for special debug info attributes.
846	    if (diIndex == static_cast<uint64_t>(Bytecode::DebugReserved::UnknownLoc))
847	      return dyn_cast<T>(UnknownLoc::get(&context));
848	
849	    // Adjust the index to account for reserved indices.
850	    diIndex -= static_cast<uint64_t>(Bytecode::DebugReserved::SIZE);
851	
852	    if (diIndex >= diCache.size())
853	      return T();
854	    if (diCache[diIndex])
855	      return dyn_cast_or_null<T>(diCache[diIndex]);
856	
857	    return dyn_cast_or_null<T>(getDebugInfo(diIndex));
858	  }
859	
860	  /// This method reads an index and converts it to a debug info attribute.
861	  template <typename T>
862	  T readAndGetDebugInfo(EncodingReader &reader) {
863	    uint64_t diIndex;
864	    if (failed(reader.readVarInt(diIndex)))
865	      return T();
866	
867	    return getDebugInfo<T>(diIndex);
868	  }
869	
870	  Attribute getDebugInfo(uint64_t diIndex) {
871	    // Check for bounds
872	    if (diIndex >= diCache.size())
873	      return Attribute();
874	    if (diCache[diIndex])
875	      return diCache[diIndex];
876	
877	    uint32_t start = diOffsets[diIndex];
878	    uint32_t end = (diIndex + 1 < diOffsets.size()) ? diOffsets[diIndex + 1]
879	                                                    : diData.size();
880	
881	    if (end < start || end > diData.size())
882	      return Attribute();
883	
884	    // Check for recursion.
885	    if (currentlyParsing.count(diIndex))
886	      return Attribute();
887	    // Mark this index as currently being parsed.
888	    currentlyParsing.insert(diIndex);
889	    [[maybe_unused]] llvm::scope_exit removeIndex(
890	        [&] { currentlyParsing.erase(diIndex); });
891	
892	    // Slice the payload to get the data for this debug info attribute.
893	    EncodingReader diReader(diData.slice(start, end - start), context);
894	    uint64_t diTag;
895	    if (failed(diReader.readVarInt(diTag)))
896	      return nullptr;
897	    ArrayRef<uint8_t> diData;
898	    if (diReader.remaining() > 0)
899	      diData = diReader.readBytes(diReader.remaining());
900	
901	    // Parse the debug info attribute based on the tag.
902	    Attribute diParsed;
903	    if (failed(parseDebugInfo(diTag, diData, diParsed)))
904	      return Attribute();
905	
906	    // Cache the result.
907	    diCache[diIndex] = diParsed;
908	    return diParsed;
909	  }
910	
911	  // di-compile-unit =:
912	  //   DebugTag[DICompileUnit]
913	  //   diFileIndex[varint] - DIFileAttr
914	  LogicalResult parseDICompileUnit(EncodingReader &reader,
915	                                   Attribute &diCompileUnit) {
916	    auto file = readAndGetDebugInfo<DIFileAttr>(reader);
917	    if (!file)
918	      return reader.emitError()
919	             << "failed to read file attribute when parsing DICompileUnitAttr";
920	
921	    diCompileUnit = DICompileUnitAttr::get(&context, file);
922	    return success();
923	  }
