1059	  // call-site =:
1060	  //  DebugTag[CallSite]
1061	  //  diCalleeIndex[varint] - LocationAttr
1062	  //  diCallerIndex[varint] - LocationAttr
1063	  LogicalResult parseCallSite(EncodingReader &reader, Attribute &callSite) {
