1109	  ArrayRef<uint32_t> diIndexOffsets;
1110	  ArrayRef<uint8_t> diData;
1111	  ArrayRef<uint32_t> diOffsets;
1112	  std::vector<Attribute> diCache;
1113	  EncodingReader &masterReader;
1114	  DenseSet<uint64_t> currentlyParsing;
