1118	//===----------------------------------------------------------------------===//
1119	// InstructionParser: Parses individual instructions within a function body.
1120	//===----------------------------------------------------------------------===//
1121	// instruction =:
1122	//   opcode[varint]
1123	//   op-specific-data          // Format depends on the opcode
1124	//
1125	
1126	namespace {
1127	
1128	// is_cuda_tile_enum_attr is now auto-generated - see AttrBytecode.inc included
1129	// above.
1130	
1131	class InstructionParser {
1132	  //===----------------------------------------------------------------------===//
1133	  // Helper for Operation Creation and Result Handling
1134	  //===----------------------------------------------------------------------===//
1135	  /// Creates an operation using OperationState and pushes its results to the
1136	  /// valueIndexList. The numResultsForValueIndex parameter controls how many
1137	  /// results are added to valueIndexList.
1138	  static LogicalResult createOperationGeneric(
1139	      OpBuilder &builder, Location loc, StringRef opNameStr,
1140	      ArrayRef<Type> resultTypes, ArrayRef<Value> operands,
1141	      ArrayRef<NamedAttribute> attributes, std::vector<Value> &valueIndexList,
1142	      SmallVectorImpl<std::unique_ptr<Region>> &parsedRegions,
1143	      std::optional<size_t> numResultsForValueIndex = std::nullopt) {
1144	    OperationState state(loc, opNameStr, operands, resultTypes, attributes);
1145	
1146	    // Add parsed regions to the operation state.
1147	    for (auto &region_ptr : parsedRegions)
1148	      state.addRegion(std::move(region_ptr));
1149	
1150	    Operation *op = builder.create(state);
1151	    // Operation creation using OperationState can fail if verification fails.
1152	    // Emit an error noting the failure.
1153	    if (!op)
1154	      return ::emitError(loc) << "failed to create operation '" << opNameStr
1155	                              << "'due to verification error.";
1156	    // Add results to the value index list. Only add numResultsForValueIndex
1157	    // results if specified (for backward compat with older bytecode that
1158	    // didn't have newer results).
1159	    size_t numToAdd = numResultsForValueIndex.value_or(op->getNumResults());
1160	    for (size_t i = 0; i < numToAdd; ++i)
1161	      valueIndexList.push_back(op->getResult(i));
1162	
1163	    return success();
1164	  }
1165	
1166	  /// Parses operand indices and returns the corresponding Values from the
1167	  /// valueIndexList. If numOperandsToRead is std::nullopt, it first reads the
1168	  /// number of operands as a VarInt. Otherwise, it uses the provided count.
1169	  static LogicalResult
1170	  parseOperands(EncodingReader &reader, Location loc,
1171	                ArrayRef<Value> valueIndexList, SmallVectorImpl<Value> &results,
1172	                std::optional<uint64_t> numOperandsToRead = std::nullopt) {
1173	    uint64_t numOperands;
1174	    if (numOperandsToRead.has_value())
1175	      numOperands = *numOperandsToRead;
1176	    else if (failed(reader.readVarInt(
1177	                 numOperands, std::numeric_limits<uint32_t>::max() - 1)))
1178	      return reader.emitError() << "failed to read operand count";
1179	
1180	    results.reserve(numOperands);
1181	    for (uint64_t i = 0; i < numOperands; ++i) {
1182	      uint64_t operandIdx;
1183	      if (failed(reader.readVarInt(operandIdx)))
1184	        return reader.emitError() << "failed to read operand index " << i;
1185	      if (operandIdx >= valueIndexList.size())
1186	        return reader.emitError()
1187	               << "operand index " << operandIdx
1188	               << " out of bounds (size=" << valueIndexList.size()
1189	               << ") for operand " << i;
1190	      results.push_back(valueIndexList[operandIdx]);
1191	    }
1192	    return success();
1193	  }
1194	
1195	  /// Helper function to parse a given block during deserialization.
1196	  static LogicalResult
1197	  parseBlock(EncodingReader &reader, OpBuilder &builder, Location loc,
1198	             Block &targetBlock, std::vector<Value> &valueIndexList,
1199	             ArrayRef<ArrayRef<uint8_t>> constants, LazyTypeTable &types,
1200	             DenseElementsAttrCache &constCache,
1201	             DebugInfoReader::Iterator &diIterator, MLIRContext &context,
1202	             const BytecodeVersion &bytecodeVersion) {
1203	    // Read number of block arguments
1204	    uint64_t numBlockArgs;
1205	    if (failed(reader.readVarInt(numBlockArgs)))
1206	      return reader.emitError() << "failed to read block argument count.";
1207	
1208	    // Record the current size of valueIndexList. Block arguments and operations
1209	    // defined within this block will be added, and then the list will be
1210	    // resized back to this original size upon exiting the block.
1211	    size_t originalValueIndexListSize = valueIndexList.size();
1212	
1213	    // Read argument types and create block arguments in the targetBlock.
1214	    for (uint64_t i = 0; i < numBlockArgs; ++i) {
1215	      Type argType = types.readAndGetType(reader);
1216	      if (!argType)
1217	        return reader.emitError()
1218	               << "failed to read block argument type: " << i;
1219	      Value arg = targetBlock.addArgument(argType, loc);
1220	      valueIndexList.push_back(arg);
1221	    }
1222	
1223	    // Read number of operations in the block.
1224	    uint64_t numOps;
1225	    if (failed(reader.readVarInt(numOps)))
1226	      return reader.emitError() << "failed to read block operation count.";
1227	
1228	    // Set insertion point to the end of the targetBlock for parsing operations.
1229	    OpBuilder::InsertionGuard guard(builder);
1230	    builder.setInsertionPointToEnd(&targetBlock);
1231	
1232	    // Parse operations in the block using the valueIndexList.
1233	    for (uint64_t i = 0; i < numOps; ++i) {
1234	      if (failed(InstructionParser::parseOperation(
1235	              reader, builder, valueIndexList, constants, types, constCache,
1236	              diIterator, context, bytecodeVersion)))
1237	        return reader.emitError()
1238	               << "failed to parse operation " << i << " in block.";
1239	    }
1240	
1241	    // Validate block structure: ensure block has terminator.
1242	    if (!targetBlock.empty()) {
1243	      Operation *lastOp = &targetBlock.back();
1244	      if (!lastOp->hasTrait<OpTrait::IsTerminator>())
1245	        return reader.emitError()
1246	               << "invalid block structure: block is expected to have a "
1247	                  "terminator "
1248	               << "operation, but the last operation '" << lastOp->getName()
1249	               << "' is not a terminator.";
1250	    } else {
1251	      return reader.emitError()
1252	             << "invalid block structure: block is expected to have a "
1253	                "terminator operation, but it is empty";
1254	    }
1255	
1256	    // Restore the valueIndexList to its original size, removing arguments
1257	    // and operation results defined within this block.
1258	    valueIndexList.resize(originalValueIndexListSize);
1259	    return success();
1260	  }
