1352	  /// Parses a scalar attribute that was serialized directly (inline).
1353	  /// Currently supports:
1354	  /// - IntegerAttr (i1 through i64)
1355	  /// - FloatAttr (all standard float types)
1356	  static LogicalResult parseScalarAttributeInline(EncodingReader &reader,
1357	                                                  MLIRContext &context,
1358	                                                  Type expectedType,
1359	                                                  Attribute &result) {
1360	    if (auto intType = dyn_cast_or_null<IntegerType>(expectedType)) {
1361	      unsigned width = intType.getWidth();
1362	      if (width == 0 || width > 64)
1363	        return reader.emitError()
1364	               << "unsupported width for inline integer attribute: " << width;
1365	
1366	      if (width == 1) {
1367	        uint8_t byte;
1368	        if (failed(reader.readLE(byte)))
1369	          return reader.emitError()
1370	                 << "failed to read byte for inline bool (i1)";
1371	        result = BoolAttr::get(&context, byte != 0);
1372	        return success();
1373	      }
1374	
1375	      uint64_t value;
1376	      if (failed(reader.readVarInt(value)))
1377	        return reader.emitError()
1378	               << "failed to read VarInt for inline integer (width=" << width
1379	               << ")";
1380	      // Validate that the value fits in the specified bit width.
1381	      if (!llvm::isUIntN(width, value))
1382	        return reader.emitError()
1383	               << "value " << value << " does not fit in " << width << " bits";
1384	
1385	      APInt apValue(width, value);
1386	      result = IntegerAttr::get(expectedType, apValue);
1387	      return success();
1388	    } else if (auto floatType = dyn_cast_or_null<FloatType>(expectedType)) {
1389	      APInt parsedAPInt;
1390	      unsigned bitWidth = APFloat::getSizeInBits(floatType.getFloatSemantics());
1391	      if (failed(parseAPInt(reader, bitWidth, parsedAPInt)))
1392	        return failure();
1393	      APFloat apFloat(floatType.getFloatSemantics(), parsedAPInt);
1394	      result = FloatAttr::get(floatType, apFloat);
1395	      return success();
1396	    }
1397	    return reader.emitError()
1398	           << "unsupported type for inline scalar parsing: " << expectedType;
1399	  }
