1401	  // Parses a DenseElementsAttr (reads an index into the constant pool).
1402	  // `expectedType` is the MLIR Type of the constant (e.g., TileType).
1403	  static LogicalResult parseConstantAttrIndex(
1404	      EncodingReader &reader, MLIRContext &context, Type expectedType,
1405	      ArrayRef<ArrayRef<uint8_t>> constants, DenseElementsAttrCache &constCache,
1406	      Attribute &result) {
1407	    uint64_t constantIndex;
1408	    if (failed(reader.readVarInt(constantIndex)))
1409	      return reader.emitError() << "failed to read constant index";
1410	    if (constantIndex >= constants.size())
1411	      return reader.emitError()
1412	             << "constant index " << constantIndex << " out of bounds";
1413	    FailureOr<Attribute> attributeOrFailure =
1414	        constCache.getOrCreate(expectedType, constants[constantIndex], context);
1415	    if (failed(attributeOrFailure))
1416	      return failure();
1417	    result = *attributeOrFailure;
1418	    return success();
1419	  }
