1474	  /// Base template: Parse attribute and convert to native type T
1475	  /// Note about expectedType:
1476	  /// - REQUIRED for inline IntegerAttr to determine the bit width.
1477	  /// - REQUIRED for DenseElementsAttr when parsing constant indices.
1478	  /// - Passed recursively for nested structures like std::optional.
1479	  /// - Optional/nullptr otherwise.
1480	  /// TODO: Auto-generate CudaTile attribute parsing from TableGen (like types).
1481	  template <typename T>
1482	  static LogicalResult
1483	  parseOpAttribute(EncodingReader &reader, MLIRContext &context,
1484	                   LazyTypeTable &types, ArrayRef<ArrayRef<uint8_t>> constants,
1485	                   DenseElementsAttrCache &constCache, T &nativeValue,
1486	                   Type expectedType = nullptr) {
1487	    Attribute parsedAttr;
1488	    // The logic here determines how to read the attribute based on the
1489	    // *expected C++ type T*, because the bytecode format doesn't explicitly
1490	    // store how each attribute was encoded (inline vs index).
1491	    if constexpr (std::is_same_v<T, UnitAttr>) {
1492	      // UnitAttr presence is stored as inline bool (i1).
1493	      BoolAttr presentAttr;
1494	      if (failed(parseScalarAttributeInline(
1495	              reader, context, IntegerType::get(&context, 1), presentAttr)))
1496	        return failure();
1497	      // Convert the parsed BoolAttr to UnitAttr (or nullptr if false)
1498	      nativeValue = presentAttr.getValue() ? UnitAttr::get(&context) : nullptr;
1499	      return success();
1500	    } else if constexpr (std::is_same_v<T, BoolAttr>) {
1501	      // BoolAttr is stored as inline bool (i1).
1502	      return parseScalarAttributeInline(
1503	          reader, context, IntegerType::get(&context, 1), nativeValue);
1504	    } else if constexpr (std::is_same_v<T, IntegerAttr>) {
1505	      if (!expectedType) {
1506	        expectedType = types.readAndGetType(reader);
1507	        if (!isa_and_nonnull<IntegerType>(expectedType))
1508	          return reader.emitError()
1509	                 << "failed to read valid IntegerType for IntegerAttr";
1510	      }
1511	      if (failed(parseScalarAttributeInline(reader, context, expectedType,
1512	                                            parsedAttr)))
1513	        return failure();
1514	      nativeValue = dyn_cast_or_null<IntegerAttr>(parsedAttr);
1515	      if (!nativeValue)
1516	        return reader.emitError()
1517	               << "failed to cast parsed attribute to IntegerAttr";
1518	      return success();
1519	    } else if constexpr (std::is_same_v<T, FloatAttr>) {
1520	      if (!expectedType) {
1521	        expectedType = types.readAndGetType(reader);
1522	        if (!isa_and_nonnull<FloatType>(expectedType))
1523	          return reader.emitError()
1524	                 << "failed to read valid FloatType for FloatAttr";
1525	      }
1526	      if (failed(parseScalarAttributeInline(reader, context, expectedType,
1527	                                            parsedAttr)))
1528	        return failure();
1529	      nativeValue = dyn_cast_or_null<FloatAttr>(parsedAttr);
1530	      if (!nativeValue)
1531	        return reader.emitError()
1532	               << "failed to cast parsed attribute to FloatAttr";
1533	      return success();
1534	    } else if constexpr (std::is_same_v<T, TypeAttr>) {
1535	      // TypeAttr is stored as an index into the type table.
1536	      Type referencedType = types.readAndGetType(reader);
1537	      if (!referencedType)
1538	        return reader.emitError()
1539	               << "failed to get referenced type for TypeAttr";
1540	      nativeValue = TypeAttr::get(referencedType);
1541	      return success();
1542	    } else if constexpr (std::is_same_v<T, StringAttr>) {
1543	      // StringAttr is stored as an index into the string table.
1544	      StringRef strRef;
1545	      if (failed(reader.readAndGetString(strRef)))
1546	        return reader.emitError() << "failed to read StringAttr.";
1547	      nativeValue = StringAttr::get(&context, strRef);
1548	      return success();
1549	    } else if constexpr (std::is_same_v<T, DenseI32ArrayAttr>) {
1550	      SmallVector<int32_t, 4> values;
1551	      if (failed(reader.readLEVarSize(values)))
1552	        return reader.emitError() << "failed to read DenseI32ArrayAttr values.";
1553	      // Validate array values.
1554	      for (int32_t val : values)
1555	        if (LLVM_UNLIKELY(val == 0x7fffffff || val == (-0x7fffffff - 1))) {
1556	          return reader.emitError()
1557	                 << "array contains unsupported value " << val;
1558	        }
1559	
1560	      nativeValue = DenseI32ArrayAttr::get(&context, values);
1561	      return success();
1562	    } else if constexpr (std::is_same_v<T, DenseI64ArrayAttr>) {
1563	      SmallVector<int64_t, 4> values;
1564	      if (failed(reader.readLEVarSize(values)))
1565	        return reader.emitError() << "failed to read DenseI64ArrayAttr values.";
1566	      // Validate array values.
1567	      for (int64_t val : values)
1568	        if (LLVM_UNLIKELY(val == 0x7fffffffffffffffLL ||
1569	                          val == (-0x7fffffffffffffffLL - 1))) {
1570	          return reader.emitError()
1571	                 << "array contains unsupported value " << val;
1572	        }
1573	
1574	      nativeValue = DenseI64ArrayAttr::get(&context, values);
1575	      return success();
1576	    } else if constexpr (std::is_same_v<std::decay_t<T>,
1577	                                        mlir::FlatSymbolRefAttr>) {
1578	      StringRef strRef;
1579	      if (failed(reader.readAndGetString(strRef)))
1580	        return reader.emitError()
1581	               << "failed to read string for FlatSymbolRefAttr.";
1582	      if (strRef.empty())
1583	        return reader.emitError() << "empty symbol reference is invalid";
1584	      nativeValue = mlir::FlatSymbolRefAttr::get(&context, strRef);
1585	      return success();
1586	    } else if constexpr (is_cuda_tile_enum_attr<T>::value) {
1587	      // Check version before parsing enum attr.
1588	      if (!isEnumAttrAvailableInVersion<T>(types.getFileVersion()))
1589	        return reader.emitError()
1590	               << "enum attribute type is not available in bytecode version "
1591	               << types.getFileVersion().toString();
1592	      return parseGenericEnumAttr(reader, context, nativeValue);
1593	    } else if constexpr (std::is_base_of_v<DenseElementsAttr, T> ||
1594	                         std::is_same_v<T, DenseElementsAttr>) {
1595	      if (!expectedType) {
1596	        Type denseMLIRType = types.readAndGetType(reader);
1597	        expectedType = dyn_cast_or_null<TileType>(denseMLIRType);
1598	        if (!expectedType)
1599	          return reader.emitError() << "failed to read valid MLIR Type for "
1600	                                       "self-contained DenseElementsAttr";
1601	      }
1602	
1603	      if (std::is_same_v<T, DenseTypedElementsAttr>) {
1604	        if (failed(parseConstantAttrIndex(reader, context, expectedType,
1605	                                          constants, constCache, parsedAttr)))
1606	          return failure();
1607	        nativeValue = dyn_cast_or_null<T>(parsedAttr);
1608	        if (!nativeValue)
1609	          return reader.emitError() << "parsed constant attribute is not the "
1610	                                       "expected type derived "
1611	                                       "from DenseElementsAttr";
1612	      } else
1613	        return reader.emitError() << "unknown DenseElementsAttr based Attr";
1614	      return success();
1615	    } else if constexpr (std::is_same_v<
1616	                             T,
1617	                             mlir::cuda_tile::AssumePredicateAttrInterface>) {
1618	      Attribute parsedAttr;
1619	      if (failed(parseSelfContainedOpAttribute(
1620	              reader, context, types, constants, constCache, parsedAttr)))
1621	        return reader.emitError() << "failed to parse self-contained attribute "
1622	                                     "for AssumePredicateAttrInterface";
1623	      nativeValue = dyn_cast_or_null<T>(parsedAttr);
1624	      if (!nativeValue)
1625	        return reader.emitError() << "failed to cast parsed attribute to "
1626	                                     "AssumePredicateAttrInterface";
1627	      return success();
1628	    } else if constexpr (std::is_same_v<T, cuda_tile::DivByAttr>) {
1629	      return parseDivByAttr(reader, context, nativeValue);
1630	#ifdef TILE_IR_INCLUDE_TESTS
1631	    } else if constexpr (std::is_same_v<T, cuda_tile::BytecodeTestValueAttr>) {
1632	      return parseBytecodeTestValueAttr(reader, context, nativeValue);
1633	#endif // TILE_IR_INCLUDE_TESTS
1634	    } else if constexpr (std::is_same_v<T, cuda_tile::SameElementsAttr>) {
1635	      DenseI64ArrayAttr valuesAttr;
1636	      if (failed(parseOpAttribute(reader, context, types, constants, constCache,
1637	                                  valuesAttr)))
1638	        return reader.emitError()
1639	               << "failed to read DenseI64ArrayAttr for SameElementsAttr";
1640	      nativeValue = cuda_tile::SameElementsAttr::get(&context, valuesAttr);
1641	      return success();
1642	    } else if constexpr (std::is_same_v<T, ArrayAttr>) {
1643	      // ArrayAttr parsing.
1644	      uint64_t arraySize;
1645	      if (failed(reader.readVarInt(arraySize,
1646	                                   std::numeric_limits<uint32_t>::max() - 1)))
1647	        return reader.emitError() << "failed to read size for ArrayAttr.";
1648	
1649	      SmallVector<Attribute> elements;
1650	      elements.reserve(arraySize);
1651	      for (uint64_t i = 0; i < arraySize; ++i) {
1652	        Attribute parsedElement;
1653	        if (failed(parseSelfContainedOpAttribute(
1654	                reader, context, types, constants, constCache, parsedElement)))
1655	          return reader.emitError()
1656	                 << "failed to parse ArrayAttr element " << i;
1657	        if (!isa_and_nonnull<TypedAttr>(parsedElement))
1658	          return reader.emitError()
1659	                 << "ArrayAttr contains non-TypedAttr elements or is null";
1660	        elements.push_back(parsedElement);
1661	      }
1662	      nativeValue = ArrayAttr::get(&context, elements);
1663	      return success();
1664	    } else if constexpr (std::is_same_v<T, DictionaryAttr>) {
1665	      uint64_t dictSize;
1666	      if (failed(reader.readVarInt(dictSize,
1667	                                   std::numeric_limits<uint32_t>::max() - 1)))
1668	        return reader.emitError() << "failed to read size for DictionaryAttr";
1669	      SmallVector<NamedAttribute> elements;
1670	      elements.reserve(dictSize);
1671	      for (uint64_t i = 0; i < dictSize; ++i) {
1672	        StringRef key;
1673	        if (failed(reader.readAndGetString(key)))
1674	          return reader.emitError()
1675	                 << "failed to read key for DictionaryAttr element " << i;
1676	        // Validate that the attribute name is not empty.
1677	        if (key.empty())
1678	          return reader.emitError()
1679	                 << "invalid empty attribute name for DictionaryAttr element "
1680	                 << i;
1681	        Attribute value;
1682	        if (failed(parseSelfContainedOpAttribute(reader, context, types,
1683	                                                 constants, constCache, value)))
1684	          return reader.emitError()
1685	                 << "failed to parse DictionaryAttr value for key " << key;
1686	        elements.emplace_back(StringAttr::get(&context, key), value);
1687	      }
1688	      if (auto duplicate = DictionaryAttr::findDuplicate(elements, false))
1689	        return reader.emitError()
1690	               << "failed to parse DictionaryAttr, duplicate key found: "
1691	               << duplicate.value().getName();
1692	      nativeValue = DictionaryAttr::get(&context, elements);
1693	      return success();
1694	    } else if constexpr (std::is_same_v<T, cuda_tile::OptimizationHintsAttr>) {
1695	      // OptimizationHintsAttr contains a DictionaryAttr.
1696	      DictionaryAttr dictAttr;
1697	      if (failed(parseOpAttribute(reader, context, types, constants, constCache,
1698	                                  dictAttr, expectedType)))
1699	        return failure();
1700	      nativeValue = cuda_tile::OptimizationHintsAttr::getChecked(
1701	          [&]() {  return reader.emitError(); }, &context, dictAttr);
1702	      if (!nativeValue)
1703	        return reader.emitError() << "failed to parse OptimizationHintsAttr";
1704	      return success();
1705	    } else if constexpr (std::is_same_v<T, cuda_tile::BoundedAttr>) {
1706	      uint8_t flagsByte;
1707	      if (failed(reader.readLE(flagsByte)))
1708	        return reader.emitError()
1709	               << "failed to read flags byte for BoundedAttr";
1710	      bool hasLb = (flagsByte & 0x01) != 0;
1711	      bool hasUb = (flagsByte & 0x02) != 0;
1712	      std::optional<int64_t> lb = std::nullopt;
1713	      std::optional<int64_t> ub = std::nullopt;
1714	      if (hasLb) {
1715	        uint64_t lbVal = 0;
1716	        if (failed(reader.readSignedVarInt(lbVal)))
1717	          return reader.emitError()
1718	                 << "failed to read lower bound for BoundedAttr";
1719	        lb = lbVal;
1720	      }
1721	      if (hasUb) {
1722	        uint64_t ubVal = 0;
1723	        if (failed(reader.readSignedVarInt(ubVal)))
1724	          return reader.emitError()
1725	                 << "failed to read upper bound for BoundedAttr";
1726	        ub = ubVal;
1727	      }
1728	      nativeValue = cuda_tile::BoundedAttr::get(&context, lb, ub);
1729	      return success();
1730	    } else {
1731	      // Add specific cases above for any other attribute types needed.
1732	      return reader.emitError()
1733	             << "attribute deserialization not implemented for "
1734	                "the requested C++ type";
1735	    }
1736	  }
1737	
1738	  /// Specialization for std::optional<T>
1739	  template <typename T>
1740	  static LogicalResult
1741	  parseOpAttribute(EncodingReader &reader, MLIRContext &context,
1742	                   LazyTypeTable &types, ArrayRef<ArrayRef<uint8_t>> constants,
1743	                   DenseElementsAttrCache &constCache,
1744	                   std::optional<T> &nativeValue, Type expectedType = nullptr) {
1745	    uint8_t isPresent;
1746	    if (failed(reader.readLE(isPresent)))
1747	      return reader.emitError()
1748	             << "failed to read presence byte for optional attribute";
1749	    if (isPresent == 0x01) {
1750	      T value;
1751	      // Call the non-optional version to parse the actual attribute value.
1752	      if (failed(parseOpAttribute(reader, context, types, constants, constCache,
1753	                                  value, expectedType)))
1754	        return failure();
1755	      nativeValue = value;
1756	    } else if (isPresent == 0x00) {
1757	      nativeValue = std::nullopt;
1758	    } else {
1759	      return reader.emitError()
1760	             << "invalid presence byte for optional attribute: "
1761	             << static_cast<int>(isPresent);
1762	    }
1763	    return success();
1764	  }
1765	
1766	public:
1767	  /// Parses a self-contained attribute, including its tag and data.
1768	  static LogicalResult parseSelfContainedOpAttribute(
1769	      EncodingReader &reader, MLIRContext &context, LazyTypeTable &types,
1770	      ArrayRef<ArrayRef<uint8_t>> constants, DenseElementsAttrCache &constCache,
1771	      Attribute &resultAttr) {
1772	    uint64_t attributeTag;
1773	    if (failed(reader.readVarInt(attributeTag)))
1774	      return reader.emitError()
1775	             << "failed to read AttributeTag for self-contained attribute.";
1776	
1777	    auto parseAttr = [&](auto &attr) {
1778	      if (failed(parseOpAttribute(reader, context, types, constants, constCache,
1779	                                  attr, nullptr)))
1780	        return failure();
1781	      resultAttr = attr;
1782	      return success();
1783	    };
1784	
1785	    switch (static_cast<Bytecode::AttributeTag>(attributeTag)) {
1786	    case Bytecode::AttributeTag::Integer: {
1787	      IntegerAttr elem;
1788	      return parseAttr(elem);
1789	    }
1790	    case Bytecode::AttributeTag::Float: {
1791	      FloatAttr elem;
1792	      return parseAttr(elem);
1793	    }
1794	    case Bytecode::AttributeTag::Bool: {
1795	      BoolAttr elem;
1796	      return parseAttr(elem);
1797	    }
1798	    case Bytecode::AttributeTag::Type: {
1799	      TypeAttr elem;
1800	      return parseAttr(elem);
1801	    }
1802	    case Bytecode::AttributeTag::String: {
1803	      StringAttr elem;
1804	      return parseAttr(elem);
1805	    }
1806	    case Bytecode::AttributeTag::Array: {
1807	      ArrayAttr elem;
1808	      return parseAttr(elem);
1809	    }
1810	    case Bytecode::AttributeTag::DenseElements: {
1811	      DenseElementsAttr elem;
1812	      return parseAttr(elem);
1813	    }
1814	    case Bytecode::AttributeTag::DivBy: {
1815	      cuda_tile::DivByAttr elem;
1816	      return parseAttr(elem);
1817	    }
1818	    case Bytecode::AttributeTag::SameElements: {
1819	      cuda_tile::SameElementsAttr elem;
1820	      return parseAttr(elem);
1821	    }
1822	    case Bytecode::AttributeTag::Dictionary: {
1823	      DictionaryAttr elem;
1824	      return parseAttr(elem);
1825	    }
1826	    case Bytecode::AttributeTag::OptimizationHints: {
1827	      cuda_tile::OptimizationHintsAttr elem;
1828	      return parseAttr(elem);
1829	    }
1830	    case Bytecode::AttributeTag::Bounded: {
1831	      cuda_tile::BoundedAttr elem;
1832	      return parseAttr(elem);
1833	    }
1834	#ifdef TILE_IR_INCLUDE_TESTS
1835	    case Bytecode::AttributeTag::BytecodeTestValue: {
1836	      cuda_tile::BytecodeTestValueAttr elem;
1837	      return parseAttr(elem);
1838	    }
1839	#endif // TILE_IR_INCLUDE_TESTS
1840	    default:
1841	      return reader.emitError() << "unsupported AttributeTag " << attributeTag
1842	                                << " for self-contained attribute";
1843	    }
1844	  }
