1989	//===----------------------------------------------------------------------===//
1990	// Function Section
1991	//===----------------------------------------------------------------------===//
1992	// function-table-section =:
1993	//   numFunctions[varint]
1994	//   function-entry*
1995	//
1996	// function-entry =:
1997	//   nameIndex[varint]         // Index into the string table.
1998	//   signatureIndex[varint]    // Index into the type table.
1999	//   functionLocIndex[varint]  // Index into the location table for the function
2000	//   instruction location info. bodyLength[varint]      // Length of the
2001	//   function body in bytes. functionBody[bytes]       // The function body data
2002	//   itself.
2003	//
2004	// function-body =:
2005	//   instruction*
2006	//
2007	namespace {
2008	struct FunctionInfo {
2009	  uint64_t nameIndex;
2010	  uint64_t signatureIndex;
2011	  uint64_t functionLocIndex;
2012	  uint8_t entryFlag;
2013	  uint64_t lengthOfFunction;
2014	  StringRef functionBody;
2015	  Attribute optimizationHints;
2016	};
2017	} // end anonymous namespace
2018	
2019	/// Parses the function table section and creates metadata for each function.
2020	static LogicalResult parseFunctionTableSection(
2021	    ArrayRef<uint8_t> payload, std::vector<FunctionInfo> &functionInfoList,
2022	    const EncodingReader &reader, LazyTypeTable &types,
2023	    ArrayRef<ArrayRef<uint8_t>> constants, DenseElementsAttrCache &constCache,
2024	    MLIRContext &context) {
2025	  EncodingReader sectionReader(payload, context);
2026	  sectionReader.inheritStringTableFrom(reader);
2027	  uint64_t numFunctions;
2028	  if (failed(sectionReader.readVarInt(numFunctions)))
2029	    return failure();
2030	  if (numFunctions > payload.size())
2031	    return sectionReader.emitError()
2032	           << "number of functions (" << numFunctions
2033	           << ") exceeds payload size (" << payload.size() << ")";
2034	  // Read each function's metadata
2035	  functionInfoList.reserve(numFunctions);
2036	  for (uint64_t i = 0; i < numFunctions; ++i) {
2037	    FunctionInfo funcInfo;
2038	    // Read the name index as a varint.
2039	    if (failed(sectionReader.readVarInt(funcInfo.nameIndex)))
2040	      return failure();
2041	    // Read the signature index as a varint.
2042	    if (failed(sectionReader.readVarInt(funcInfo.signatureIndex)))
2043	      return failure();
2044	    // Read the entry flag byte.
2045	    if (failed(sectionReader.readLE(funcInfo.entryFlag)))
2046	      return failure();
2047	    // Read the function location index as a varint.
2048	    if (failed(sectionReader.readVarInt(funcInfo.functionLocIndex)))
2049	      return failure();
2050	
2051	    // Read optimization hints if the flag is set for EntryOp.
2052	    bool isEntry =
2053	        (funcInfo.entryFlag &
2054	         static_cast<uint8_t>(Bytecode::FunctionFlags::KindKernel)) != 0;
2055	    bool hasOptHints =
2056	        (funcInfo.entryFlag &
2057	         static_cast<uint8_t>(Bytecode::FunctionFlags::HasOptimizationHints)) !=
2058	        0;
2059	    if (isEntry && hasOptHints) {
2060	      if (failed(InstructionParser::parseSelfContainedOpAttribute(
2061	              sectionReader, context, types, constants, constCache,
2062	              funcInfo.optimizationHints)))
2063	        return failure();
2064	    }
2065	
2066	    // Read the length of the function as a varint.
2067	    if (failed(sectionReader.readVarInt(funcInfo.lengthOfFunction)))
2068	      return failure();
2069	
2070	    // Validate function length.
2071	    if (funcInfo.lengthOfFunction > std::numeric_limits<size_t>::max())
2072	      return sectionReader.emitError()
2073	             << "function body length " << funcInfo.lengthOfFunction
2074	             << " exceeds maximum addressable size ("
2075	             << std::numeric_limits<size_t>::max() << " bytes)";
2076	
2077	    // Check that we have enough remaining bytes.
2078	    if (funcInfo.lengthOfFunction > sectionReader.remaining())
2079	      return sectionReader.emitError()
2080	             << "function body length " << funcInfo.lengthOfFunction
2081	             << " exceeds remaining bytecode data ("
2082	             << sectionReader.remaining() << " bytes)";
2083	
2084	    // Read the function body as raw bytes.
2085	    ArrayRef<uint8_t> bodyBytes;
2086	    if (failed(sectionReader.readBytes(funcInfo.lengthOfFunction, bodyBytes)))
2087	      return failure();
2088	
2089	    if (bodyBytes.empty() && funcInfo.lengthOfFunction > 0)
2090	      return sectionReader.emitError()
2091	             << "failed to read " << funcInfo.lengthOfFunction
2092	             << " bytes for function body";
2093	
2094	    funcInfo.functionBody =
2095	      StringRef(reinterpret_cast<const char *>(bodyBytes.data()),
2096	                    funcInfo.lengthOfFunction);
2097	
2098	    functionInfoList.emplace_back(funcInfo);
2099	  }
2100	  return success();
2101	}
2102	
2103	/// Parses the function body bytecode and creates the corresponding operations.
2104	static LogicalResult
2105	parseFunctionBody(ArrayRef<uint8_t> bodyBytes, OpBuilder &innerBuilder,
2106	                  std::vector<Value> &valueIndexList,
2107	                  DebugInfoReader::Iterator &diIterator,
2108	                  ArrayRef<ArrayRef<uint8_t>> constants, LazyTypeTable &types,
2109	                  DenseElementsAttrCache &constCache, MLIRContext &context,
2110	                  const EncodingReader &mainFileStreamReader,
2111	                  const BytecodeVersion &bytecodeVersion) {
2112	  EncodingReader bodyReader(bodyBytes, context);
2113	  // Inherit the string table from the main file stream reader.
2114	  bodyReader.inheritStringTableFrom(mainFileStreamReader);
2115	
2116	  while (bodyReader.remaining() > 0)
2117	    if (failed(InstructionParser::parseOperation(
2118	            bodyReader, innerBuilder, valueIndexList, constants, types,
2119	            constCache, diIterator, context, bytecodeVersion)))
2120	      return failure();
2121	  return success();
2122	}
2123	
2124	/// Creates a function based on the parsed FunctionInfo.
2125	static LogicalResult createFunction(
2126	    const FunctionInfo &funcInfo, OpBuilder &builder, OpBuilder &funcBuilder,
2127	    const EncodingReader &reader, LazyTypeTable &types,
2128	    DebugInfoReader &debuginfo, ArrayRef<ArrayRef<uint8_t>> constants,
2129	    DenseElementsAttrCache &constCache, std::vector<Value> &valueIndexList,
2130	    MLIRContext &context, const BytecodeVersion &bytecodeVersion) {
2131	  StringRef funcNameStr;
2132	  if (failed(reader.getString(funcInfo.nameIndex, funcNameStr, context)))
2133	    return reader.emitError() << "failed to get function name string at index "
2134	                              << funcInfo.nameIndex;
2135	  if (funcNameStr.empty())
2136	    return reader.emitError()
2137	           << "function name at index " << funcInfo.nameIndex << " is empty";
2138	  StringAttr funcName = builder.getStringAttr(funcNameStr);
2139	  // Get the function type lazily from the type table.
2140	  if (funcInfo.signatureIndex >= types.size())
2141	    return reader.emitError()
2142	           << "function signature index " << funcInfo.signatureIndex
2143	           << " out of bounds for function '" << funcNameStr << "'";
2144	  Type signatureType = types.getType(funcInfo.signatureIndex);
2145	  if (!signatureType)
2146	    return reader.emitError()
2147	           << "failed to parse type at index " << funcInfo.signatureIndex
2148	           << " for function '" << funcNameStr;
2149	  FunctionType funcType = mlir::dyn_cast<FunctionType>(signatureType);
2150	  if (!funcType)
2151	    return reader.emitError()
2152	           << "function signature index " << funcInfo.signatureIndex
2153	           << " does not refer to a function type for function '" << funcNameStr
2154	           << "', got type: " << signatureType;
2155	  auto diIterator = debuginfo.getIterator(funcInfo.functionLocIndex);
2156	  auto funcLoc = diIterator.next<LocationAttr>();
2157	  if (!funcLoc)
2158	    return reader.emitError()
2159	           << "failed to read function location for '" << funcNameStr << "'";
2160	
2161	  // Determine if it's an EntryOp based on the flag
2162	  bool isEntry =
2163	      (funcInfo.entryFlag &
2164	       static_cast<uint8_t>(Bytecode::FunctionFlags::KindKernel)) != 0;
2165	
2166	  // TODO: Handle visibility flag (Bit 0) when supported.
2167	
2168	  SmallVector<Attribute, 4> argAttrs;
2169	  argAttrs.reserve(funcType.getNumInputs());
2170	  for (size_t i = 0; i < funcType.getNumInputs(); ++i)
2171	    argAttrs.emplace_back(builder.getDictionaryAttr({}));
2172	  SmallVector<Attribute, 4> retAttrs;
2173	  retAttrs.reserve(funcType.getNumResults());
2174	  ArrayAttr funcArgAttrs = builder.getArrayAttr(argAttrs);
2175	  for (size_t i = 0; i < funcType.getNumResults(); ++i)
2176	    retAttrs.emplace_back(builder.getDictionaryAttr({}));
2177	  ArrayAttr funcRetAttrs = builder.getArrayAttr(retAttrs);
2178	
2179	  // Create the appropriate operation type
2180	  mlir::FunctionOpInterface funcOpIFace;
2181	  if (isEntry) {
2182	    // Use optimization hints from bytecode or create default empty hints
2183	    OptimizationHintsAttr funcOptHintAttr =
2184	        funcInfo.optimizationHints
2185	            ? dyn_cast<OptimizationHintsAttr>(funcInfo.optimizationHints)
2186	            : OptimizationHintsAttr::get(&context,
2187	                                         builder.getDictionaryAttr({}));
2188	
2189	    if (!funcOptHintAttr) {
2190	      return reader.emitError()
2191	             << "invalid optimization hints attribute for function '"
2192	             << funcNameStr << "'";
2193	    }
2194	
2195	    funcOpIFace = cuda_tile::EntryOp::create(
2196	        funcBuilder, funcLoc, funcName, TypeAttr::get(funcType), funcArgAttrs,
2197	        funcRetAttrs, funcOptHintAttr);
2198	  } else {
2199	    return reader.emitError()
2200	           << "un-expected non-entry function '" << funcNameStr << "'";
2201	  }
2202	
2203	  auto &entryBlock = *funcOpIFace.addEntryBlock();
2204	  OpBuilder innerBuilder(&entryBlock, entryBlock.begin());
2205	  valueIndexList.clear();
2206	  for (BlockArgument arg : entryBlock.getArguments())
2207	    valueIndexList.emplace_back(arg);
2208	  ArrayRef<uint8_t> bodyBytes(
2209	      reinterpret_cast<const uint8_t *>(funcInfo.functionBody.data()),
2210	      funcInfo.functionBody.size());
2211	  // Parse the function body  instructions.
2212	  if (failed(parseFunctionBody(bodyBytes, innerBuilder, valueIndexList,
2213	                               diIterator, constants, types, constCache,
2214	                               context, reader, bytecodeVersion)))
2215	    return reader.emitError() << "failed to parse function body for function '"
2216	                              << funcNameStr << "'";
2217	  return success();
2218	}
