2221	// Global Section
2222	//===----------------------------------------------------------------------===//
2223	// global-section =:
2224	//   numGlobals[varint]
2225	//   padding[bytes]             // Align to 8 bytes.
2226	//   global-entry*
2227	//
2228	// global-entry =:
2229	//   symbolNameIndex[varint]    // Index into the string table.
2230	//   valueTypeIndex[varint]     // Index into the type table.
2231	//   constantValueIndex[varint] // Index into the constant table.
2232	//   alignment[varint]          // Alignment of the global variable.
2233	//   symbolVisibility[varint]   // Symbol visibility (0=Public, 1=Private).
2234	//   constant[varint]           // Whether the global is constant (0=false,
2235	//   1=true).
2236	//
2237	namespace {
2238	struct GlobalInfo {
2239	  uint64_t symbolNameIndex;
2240	  uint64_t valueTypeIndex;
2241	  uint64_t constantValueIndex;
2242	  uint64_t alignment;
2243	  uint64_t symbolVisibility;
2244	  uint64_t constant;
2245	};
2246	} // end anonymous namespace
2247	
2248	/// Parses the global section and creates metadata for each global variable.
2249	static LogicalResult
2250	parseGlobalSection(ArrayRef<uint8_t> payload, const EncodingReader &mainReader,
2251	                   std::vector<GlobalInfo> &globalInfoList,
2252	                   MLIRContext &context,
2253	                   const BytecodeVersion &bytecodeVersion) {
2254	  EncodingReader sectionReader(payload, context);
2255	  sectionReader.inheritStringTableFrom(mainReader);
2256	
2257	  uint64_t numGlobals;
2258	  if (failed(sectionReader.readVarInt(numGlobals)))
2259	    return sectionReader.emitError() << "failed to read number of global.";
2260	
2261	  // Determine minimum size based on bytecode version.
2262	  // Version 13.1: 4 varints (symbolNameIndex, valueTypeIndex,
2263	  // constantValueIndex, alignment) Version 13.3+: 6 varints (added
2264	  // symbolVisibility and constant)
2265	  auto version_13_3 = BytecodeVersion::fromVersion(13, 3, 0);
2266	  size_t kMinGlobalInfoSize = (bytecodeVersion >= *version_13_3) ? 6 : 4;
2267	
2268	  if (numGlobals >
2269	      (payload.size() - sectionReader.currentOffset()) / kMinGlobalInfoSize) {
2270	    return sectionReader.emitError()
2271	           << "number of globals (" << numGlobals << ") exceeds the maximum of "
2272	           << (payload.size() - sectionReader.currentOffset()) /
2273	                  kMinGlobalInfoSize
2274	           << " that can fit in the remaining payload of "
2275	           << (payload.size() - sectionReader.currentOffset()) << " bytes.";
2276	  }
2277	
2278	  globalInfoList.reserve(numGlobals);
2279	
2280	  for (uint64_t i = 0; i < numGlobals; ++i) {
2281	    GlobalInfo globalInfo;
2282	    // 1. Read symbol name index.
2283	    if (failed(sectionReader.readVarInt(globalInfo.symbolNameIndex)))
2284	      return sectionReader.emitError()
2285	             << "failed to read global symbol name string.";
2286	
2287	    // 2. Read type index of the value.
2288	    if (failed(sectionReader.readVarInt(globalInfo.valueTypeIndex)))
2289	      return sectionReader.emitError() << "failed to read global value type";
2290	
2291	    // 3. Read constant index for the value.
2292	    if (failed(sectionReader.readVarInt(globalInfo.constantValueIndex)))
2293	      return sectionReader.emitError()
2294	             << "failed to read global value constant index";
2295	
2296	    // 4. Read alignment.
2297	    if (failed(sectionReader.readVarInt(globalInfo.alignment)))
2298	      return sectionReader.emitError() << "failed to read global alignment";
2299	
2300	    // 5. Read symbol_visibility (added in version 13.3).
2301	    if (bytecodeVersion >= *version_13_3) {
2302	      if (failed(sectionReader.readVarInt(globalInfo.symbolVisibility)))
2303	        return sectionReader.emitError()
2304	               << "failed to read global symbol visibility";
2305	    } else {
2306	      // For older bytecode versions (< 13.3), use default value (Public = 0).
2307	      globalInfo.symbolVisibility = 0; // SymbolVisibility::Public
2308	    }
2309	
2310	    // 6. Read constant (added in version 13.3).
2311	    if (bytecodeVersion >= *version_13_3) {
2312	      if (failed(sectionReader.readVarInt(globalInfo.constant)))
2313	        return sectionReader.emitError()
2314	               << "failed to read global constant flag";
2315	    } else {
2316	      // For older bytecode versions (< 13.3), use default value (false).
2317	      globalInfo.constant = 0;
2318	    }
2319	
2320	    globalInfoList.emplace_back(globalInfo);
2321	  }
2322	  return success();
2323	}
2324	
2325	//===----------------------------------------------------------------------===//
2326	// Producer Section
2327	//===----------------------------------------------------------------------===//
2328	// producer-section =:
2329	//   producerStringIndex[varint]  // Index into the string table
2330	//
2331	/// Parses the producer section and returns the producer string.
2332	static LogicalResult parseProducerSection(ArrayRef<uint8_t> payload,
2333	                                          const EncodingReader &mainReader,
2334	                                          std::optional<StringRef> &producer,
2335	                                          MLIRContext &context) {
2336	  EncodingReader sectionReader(payload, context);
2337	  sectionReader.inheritStringTableFrom(mainReader);
2338	
2339	  uint64_t producerIndex;
2340	  if (failed(sectionReader.readVarInt(producerIndex)))
2341	    return sectionReader.emitError() << "failed to read producer string index";
2342	
2343	  StringRef producerStr;
2344	  if (failed(sectionReader.getString(producerIndex, producerStr, context)))
2345	    return sectionReader.emitError()
2346	           << "failed to get producer string at index " << producerIndex;
2347	
2348	  producer = producerStr;
2349	  return success();
2350	}
2351	
2352	/// Creates a global (cuda_tile::GlobalOp) based on the parsed GlobalInfo.
2353	static LogicalResult
2354	createGlobal(const GlobalInfo &globalInfo, OpBuilder &builder,
2355	             const EncodingReader &reader, LazyTypeTable &types,
2356	             ArrayRef<ArrayRef<uint8_t>> constants,
2357	             DenseElementsAttrCache &constCache, DebugInfoReader &debuginfo,
2358	             MLIRContext &context) {
2359	  if (globalInfo.constantValueIndex >= constants.size())
2360	    return reader.emitError() << "global value constant index out of bounds";
2361	
2362	  StringRef symNameStr;
2363	  if (failed(reader.getString(globalInfo.symbolNameIndex, symNameStr, context)))
2364	    return reader.emitError()
2365	           << "failed to get global symbol name string for index "
2366	           << globalInfo.symbolNameIndex;
2367	  if (symNameStr.empty())
2368	    return reader.emitError() << "global symbol name at index "
2369	                              << globalInfo.symbolNameIndex << " is empty";
2370	
2371	  FailureOr<Attribute> valueAttr =
2372	      constCache.getOrCreate(types.getType(globalInfo.valueTypeIndex),
2373	                             constants[globalInfo.constantValueIndex], context);
2374	  if (failed(valueAttr))
2375	    return failure();
2376	
2377	  auto denseValueAttr = dyn_cast<DenseTypedElementsAttr>(*valueAttr);
2378	  if (!denseValueAttr)
2379	    return reader.emitError()
2380	           << "parsed global constant attribute is not the expected type "
2381	              "derived from DenseTypedElementsAttr";
2382	
2383	  // Global variables must not have DILocAttr location type because CudaTile
2384	  // supports only local scope. Therefore, global variables must have UnknownLoc
2385	  // location type - the only other legal location type.
2386	  //
2387	  // Convert symbolVisibility from serialized integer to enum, then to
2388	  // attribute.
2389	  auto symbolVisibility =
2390	      symbolizeSymbolVisibility(globalInfo.symbolVisibility);
2391	  if (!symbolVisibility.has_value())
2392	    return reader.emitError() << "invalid symbol visibility value: "
2393	                              << globalInfo.symbolVisibility;
2394	
2395	  auto symbolVisibilityAttr =
2396	      cuda_tile::SymbolVisibilityAttr::get(&context, symbolVisibility.value());
2397	
2398	  // Convert constant from uint64_t (0=not present, !=0=present) to UnitAttr.
2399	  // UnitAttr is present (non-null) when constant!=0, otherwise nullptr.
2400	  auto constantAttr =
2401	      (globalInfo.constant != 0) ? mlir::UnitAttr::get(&context) : nullptr;
2402	
2403	  cuda_tile::GlobalOp::create(builder, UnknownLoc::get(&context),
2404	                              builder.getStringAttr(symNameStr), denseValueAttr,
2405	                              builder.getI64IntegerAttr(globalInfo.alignment),
2406	                              constantAttr, symbolVisibilityAttr);
2407	  return success();
2408	}
