2410	//===----------------------------------------------------------------------===//
2411	// readBytecode Function Implementation
2412	// Implements the core functionality of reading bytecode from a memory buffer
2413	// and constructing the corresponding cuda_tile::ModuleOp.
2414	//===----------------------------------------------------------------------===//
2415	
2416	std::optional<size_t> cuda_tile::getBytecodeSize(const char *bytecodeBuffer) {
2417	  if (!isTileIRBytecode(bytecodeBuffer))
2418	    return std::nullopt;
2419	
2420	  auto charBuffer = reinterpret_cast<const unsigned char*>(bytecodeBuffer);
2421	  if (charBuffer[sizeof(kTileIRBytecodeMagic)] == 0)
2422	    return std::nullopt;
2423	
2424	  // Build a buffer assuming we have the maximum size of the bytecode, we'll
2425	  // infer the actual size as we parse the bytecode.
2426	  ArrayRef<uint8_t> bytecodeData(
2427	      reinterpret_cast<const uint8_t *>(bytecodeBuffer),
2428	      SIZE_MAX - reinterpret_cast<uintptr_t>(bytecodeBuffer));
2429	
2430	  // Set up the reader and context.
2431	  MLIRContext context(MLIRContext::Threading::DISABLED);
2432	  EncodingReader reader(bytecodeData, context);
2433	  ScopedDiagnosticHandler handler(&context, [](Diagnostic &diag) {
2434	    // Ignore all errors.
2435	  });
2436	
2437	  // Parse the header of the bytecode.
2438	  BytecodeVersion version;
2439	  if (failed(parseHeader(reader, context, version)))
2440	    return std::nullopt;
2441	
2442	  // Parse the sections until we reach the end of the bytecode. We don't
2443	  // actually try to reason about the section data, we just want to know the
2444	  // sizes.
2445	  std::array<bool, Section::NumSections> seenSections;
2446	  seenSections.fill(false);
2447	  while (true) {
2448	    // Parse the next section.
2449	    SectionHeader header;
2450	    if (failed(parseSectionHeader(reader, header, context)) ||
2451	        failed(reader.skip(header.length)) ||
2452	        std::exchange(seenSections[header.sectionID], true))
2453	      return std::nullopt;
2454	
2455	    // Check for the end of the bytecode stream.
2456	    if (header.sectionID == Section::EndOfBytecode)
2457	      return reader.currentOffset();
2458	  }
2459	}
2460	
2461	OwningOpRef<cuda_tile::ModuleOp>
2462	cuda_tile::readBytecode(llvm::MemoryBufferRef bytecodeBuffer,
2463	                        MLIRContext &context) {
2464	  ArrayRef<uint8_t> bytecodeData(
2465	      reinterpret_cast<const uint8_t *>(bytecodeBuffer.getBufferStart()),
2466	      bytecodeBuffer.getBufferSize());
2467	
2468	  EncodingReader reader(bytecodeData, context);
2469	  DebugInfoReader debuginfo(context, reader);
2470	
2471	  BytecodeVersion bytecodeVersion;
2472	  if (failed(parseHeader(reader, context, bytecodeVersion)))
2473	    return reader.emitError() << "failed to parse bytecode header", nullptr;
2474	
2475	  // Store section payloads to allow parsing in a specific order later.
2476	  std::array<std::optional<ArrayRef<uint8_t>>, Section::NumSections + 1>
2477	      sectionPayloads;
2478	
2479	  // Discover all sections and store their payloads.
2480	  while (true) {
2481	    SectionHeader header;
2482	    if (failed(parseSectionHeader(reader, header, context)))
2483	      return reader.emitError() << "failed to parse section header", nullptr;
2484	
2485	    // Check for the end of the bytecode stream.
2486	    if (header.sectionID == Section::EndOfBytecode) {
2487	      if (reader.remaining() != 0) {
2488	        reader.emitError() << "end section is not the last section";
2489	        return nullptr;
2490	      }
2491	      break;
2492	    }
2493	
2494	    auto validateSectionAlignment = [&](uint64_t requiredAlignment) -> bool {
2495	      if (!header.hasAlignment || (header.alignment % requiredAlignment) != 0) {
2496	        reader.emitError() << "section " << static_cast<int>(header.sectionID)
2497	                           << " must have alignment that is a multiple of "
2498	                           << requiredAlignment << " bytes, but "
2499	                           << (header.hasAlignment
2500	                                   ? ("has alignment of " +
2501	                                      std::to_string(header.alignment))
2502	                                   : "has no alignment flag set");
2503	        return false;
2504	      }
2505	      return true;
2506	    };
2507	
2508	    switch (header.sectionID) {
2509	    case Section::String:
2510	    case Section::Type:
2511	      if (!validateSectionAlignment(alignof(uint32_t)))
2512	        return nullptr;
2513	      break;
2514	    case Section::Constant:
2515	    case Section::Debug:
2516	    case Section::Func:
2517	      if (!validateSectionAlignment(alignof(uint64_t)))
2518	        return nullptr;
2519	      break;
2520	    case Section::Global:
2521	      // Global section has variable alignment requirements, skip validation
2522	      [[fallthrough]];
2523	    default:
2524	      // Unknown sections or sections with variable alignment requirements
2525	      break;
2526	    }
2527	
2528	    // Read the section payload.
2529	    if (header.length > reader.remaining()) {
2530	      reader.emitError() << "section length " << header.length
2531	                         << " exceeds remaining bytecode data. "
2532	                         << reader.remaining();
2533	      return nullptr;
2534	    }
2535	    ArrayRef<uint8_t> payload;
2536	    if (failed(reader.readBytes(header.length, payload)))
2537	      return reader.emitError() << "failed to read section payload", nullptr;
2538	
2539	    sectionPayloads[header.sectionID] = payload;
2540	  }
2541	
2542	  // Initialize data structures for parsed sections.
2543	  LazyTypeTable types(context);
2544	  std::vector<ArrayRef<uint8_t>> constants;
2545	  std::vector<FunctionInfo> functionInfoList;
2546	  std::vector<Value> valueIndexList;
2547	  DenseElementsAttrCache globalConstCache;
2548	  std::vector<GlobalInfo> globalInfoList;
2549	  std::optional<StringRef> producer;
2550	
2551	  // Process sections in dependency order using their stored payloads.
2552	  // Parse String Section.
2553	  if (sectionPayloads[Section::String].has_value()) {
2554	    if (failed(parseStringSection(*sectionPayloads[Section::String], reader,
2555	                                  context)))
2556	      return reader.emitError() << "failed to parse string section", nullptr;
2557	  } else {
2558	    return reader.emitError() << "string section is mandatory", nullptr;
2559	  }
2560	  // Parse Producer Section (optional).
2561	  if (sectionPayloads[Section::Producer].has_value())
2562	    if (failed(parseProducerSection(*sectionPayloads[Section::Producer], reader,
2563	                                    producer, context)))
2564	      return reader.emitError() << "failed to parse producer section", nullptr;
2565	  // Parse Type Section.
2566	  if (sectionPayloads[Section::Type].has_value())
2567	    if (failed(parseTypeSection(*sectionPayloads[Section::Type], types, context,
2568	                                bytecodeVersion)))
2569	      return reader.emitError() << "failed to parse type section", nullptr;
2570	  // Parse Constant Section.
2571	  if (sectionPayloads[Section::Constant].has_value())
2572	    if (failed(parseConstantSection(*sectionPayloads[Section::Constant],
2573	                                    constants, context)))
2574	      return reader.emitError() << "failed to parse constant section", nullptr;
2575	  // Parse Global Section.
2576	  if (sectionPayloads[static_cast<uint8_t>(Bytecode::Section::Global)]
2577	          .has_value())
2578	    if (failed(parseGlobalSection(
2579	            *sectionPayloads[static_cast<uint8_t>(Bytecode::Section::Global)],
2580	            reader, globalInfoList, context, bytecodeVersion)))
2581	      return reader.emitError() << "failed to parse global section", nullptr;
2582	  // Parse Function Section.
2583	  if (sectionPayloads[Section::Func].has_value()) {
2584	    if (failed(parseFunctionTableSection(*sectionPayloads[Section::Func],
2585	                                         functionInfoList, reader, types,
2586	                                         constants, globalConstCache, context)))
2587	      return reader.emitError() << "failed to parse function section", nullptr;
2588	  } else {
2589	    return reader.emitError() << "function section is mandatory", nullptr;
2590	  }
2591	  // Parse Debug Section.
2592	  if (sectionPayloads[Section::Debug].has_value())
2593	    if (failed(parseDebugSection(*sectionPayloads[Section::Debug], debuginfo,
2594	                                 context)))
2595	      return reader.emitError() << "failed to parse debug section", nullptr;
2596	
2597	  OpBuilder moduleBuilder(&context);
2598	  OwningOpRef<cuda_tile::ModuleOp> cudaTileModule(
2599	      cuda_tile::ModuleOp::create(moduleBuilder, UnknownLoc::get(&context),
2600	                                  "kernels", producer.value_or("")));
2601	  OpBuilder builder(cudaTileModule->getBody());
2602	  OpBuilder funcBuilder(&cudaTileModule->getBody().front(),
2603	                        cudaTileModule->getBody().front().begin());
2604	  for (const auto &globalInfo : globalInfoList)
2605	    if (failed(createGlobal(globalInfo, builder, reader, types, constants,
2606	                            globalConstCache, debuginfo, context)))
2607	      return reader.emitError() << "failed to create global from bytecode",
2608	             nullptr;
2609	  for (const auto &funcInfo : functionInfoList)
2610	    if (failed(createFunction(funcInfo, builder, funcBuilder, reader, types,
2611	                              debuginfo, constants, globalConstCache,
2612	                              valueIndexList, context, bytecodeVersion)))
2613	      return reader.emitError() << "failed to create function from bytecode",
2614	             nullptr;
2615	  if (failed(verify(cudaTileModule.get()))) {
2616	    ::emitError(UnknownLoc::get(&context))
2617	        << "verification failed for deserialized cuda_tile::ModuleOp";
2618	    return nullptr;
2619	  }
2620	  return cudaTileModule;
2621	}
