250	/// Generates the flags field serialization for optional attributes and
251	/// operands. Version checking is only done for optional attributes and
252	/// operands.
253	///
254	/// The flags field is a varint that uses individual bits to encode the presence
255	/// of optional attributes and operands. The bit layout is version-ordered to
256	/// ensure backward compatibility:
257	///   - Bits are assigned in version order (earliest versions first)
258	///   - Within each version: attributes first, then operands (declaration order)
259	///   - This prevents bit layout shifts when new optional fields are added.
260	///
261	/// Special case: UnitAttr presence is ONLY encoded in the flags field.
262	/// No actual attribute data is written to the stream for UnitAttr.
263	static void generateFlagsFieldSerialization(const Operator &op,
264	                                            raw_ostream &os) {
265	  // Get version-ordered bit assignments and earliest optional field version.
266	  auto [bitAssignments, minOptionalVersion] =
267	      getVersionOrderedBitAssignments(op);
268	  if (bitAssignments.empty())
269	    return;
270	
271	  std::string opVersion = extractVersionFromOperation(op);
272	  os << "  // Write flags field for optional attributes/operands.\n"
273	     << "  uint64_t flags = 0;\n";
274	
275	  // Set flags bits for optional attributes and validate their versions.
276	  for (const auto &namedAttr : op.getAttributes()) {
277	    if (namedAttr.attr.isOptional()) {
278	      StringRef attrName = namedAttr.name;
279	      std::string getterName = op.getGetterName(attrName);
280	      size_t bitPos = bitAssignments.lookup(attrName);
281	
282	        auto [majorStr, minorStr] = extractVersionFromAttribute(namedAttr, op);
283	        std::string version = majorStr + "." + minorStr;
284	
285	        if (version == opVersion) {
286	          // Attribute from original operation - simple flag setting.
287	          os << llvm::formatv(R"(
288	  auto flagsAttrValue_{0} = op.{1}();
289	  if (flagsAttrValue_{0}) flags |= (1ULL << {2});
290	)",
291	                              attrName, getterName, bitPos);
292	        } else {
293	          // Versioned attribute - validate version compatibility.
294	          os << llvm::formatv(R"(
295	  auto flagsAttrValue_{0} = op.{1}();
296	  if (flagsAttrValue_{0}) {{
297	    auto flagsRequiredVersionFor_{0} = BytecodeVersion::fromVersion({2}, {3}, 0);
298	    assert(flagsRequiredVersionFor_{0} && "TableGen should guarantee valid versions");
299	    if (config.bytecodeVersion < *flagsRequiredVersionFor_{0}) {{
300	      op.emitError() << "optional attribute '{0}' is provided but requires bytecode version {4}, targeting " << config.bytecodeVersion.toString();
301	      return failure();
302	    }
303	    // Attribute provided and compatible - set flag.
304	    flags |= (1ULL << {5});
305	  }
306	  // Attribute not provided - don't set flag.
307	)",
308	                              attrName, getterName, majorStr, minorStr, version,
309	                              bitPos);
310	        }
311	    }
312	  }
313	
314	  // Set flags bits for optional operands and validate them.
315	  if (op.getTrait("::mlir::OpTrait::AttrSizedOperandSegments")) {
316	    for (const auto &[operandIndex, odsOperand] :
317	         llvm::enumerate(op.getOperands())) {
318	      if (!odsOperand.isOptional()
319	      ) {
320	        // Validate that required operands were introduced with the operation
321	        // itself.
322	        auto [majorStr, minorStr] = extractVersionFromOperand(operandIndex, op);
323	        std::string version = majorStr + "." + minorStr;
324	        if (version != opVersion)
325	          PrintFatalError("Required operand '" + odsOperand.name.str() +
326	                          "' in operation '" + op.getOperationName() +
327	                          "' was introduced after the operation.");
328	      } else if (odsOperand.isOptional()) {
329	        StringRef operandName = odsOperand.name;
330	        size_t bitPos = bitAssignments.lookup(operandName);
331	
332	        os << llvm::formatv(R"(
333	  auto operandGroup_{0} = op.getODSOperands({0});
334	)",
335	                            operandIndex);
336	
337	          auto [majorStr, minorStr] =
338	              extractVersionFromOperand(operandIndex, op);
339	          std::string version = majorStr + "." + minorStr;
340	
341	          if (version == opVersion) {
342	            // Operand from original operation - no version checking needed.
343	            os << llvm::formatv(R"(
344	  if (!operandGroup_{0}.empty()) flags |= (1ULL << {1});
345	)",
346	                                operandIndex, bitPos);
347	          } else {
348	            // Versioned operand - validate version compatibility.
349	            os << llvm::formatv(R"(
350	  if (!operandGroup_{0}.empty()) {{
351	    auto requiredVersionFor_{1} = BytecodeVersion::fromVersion({2}, {3}, 0);
352	    assert(requiredVersionFor_{1} && "TableGen should guarantee valid versions");
353	    if (config.bytecodeVersion < *requiredVersionFor_{1}) {{
354	      op.emitError() << "optional operand '{1}' is provided but requires bytecode version {4}, targeting " << config.bytecodeVersion.toString();
355	      return failure();
356	    }
357	    // Operand provided and compatible - set flag.
358	    flags |= (1ULL << {5});
359	  }
360	  // Operand not provided - don't set flag.
361	)",
362	                                operandIndex, operandName, majorStr, minorStr,
363	                                version, bitPos);
364	          }
365	      }
366	    }
367	  }
368	
369	  // Backward Compatibility: Only generate version check if the first optional
370	  // field was added AFTER the operation's baseline version. This allows newer
371	  // writers (e.g., 13.2) to target older bytecode formats (e.g., 13.1 via
372	  // --bytecode-version=13.1) for compatibility with older readers. If optional
373	  // fields existed from the operation's baseline, flags field is always
374	  // written.
375	  std::string minOptionalVersionStr =
376	      minOptionalVersion
377	          ? (minOptionalVersion->first + "." + minOptionalVersion->second)
378	          : "";
379	  bool needsVersionCheck =
380	      minOptionalVersion && (minOptionalVersionStr != opVersion);
381	
382	  if (needsVersionCheck) {
383	    auto [majorStr, minorStr] = *minOptionalVersion;
384	    os << llvm::formatv(
385	        R"(  // Only write flags if targeting version >= {0}.{1} (first optional field version)
386	  auto requiredVersionForFlags = BytecodeVersion::fromVersion({0}, {1}, 0);
387	  assert(requiredVersionForFlags && "TableGen should guarantee valid versions");
388	  if (config.bytecodeVersion >= *requiredVersionForFlags) {{
389	    writer.writeVarInt(flags);
390	  }
391	
392	)",
393	        majorStr, minorStr);
394	  } else {
395	    // Flags field always exists for this operation.
396	    os << "  writer.writeVarInt(flags);\n\n";
397	  }
398	}
